//! Manages Kafka partition assignments and revocations for a consumer
//! application.
//!
//! This module integrates Kafka's rebalance callbacks with internal partition
//! management logic, ensuring dynamic partition management in response to
//! consumer group changes. It encapsulates configuration and state management
//! for partitions, connecting processing logic with the consumer's behavior
//! during rebalance events.

use std::collections::hash_map::Entry;
use std::future::ready;
use std::sync::Arc;
use std::time::Duration;

use futures::stream::FuturesUnordered;
use futures::StreamExt;
use parking_lot::Mutex;
use rdkafka::consumer::{BaseConsumer, CommitMode, Consumer, ConsumerContext, Rebalance};
use rdkafka::{ClientContext, Offset, TopicPartitionList};
use tokio::runtime::Handle;
use tracing::{debug, error, info, warn};

use crate::consumer::partition::PartitionManager;
use crate::consumer::{ConsumerConfiguration, Managers, MessageHandler, WatermarkVersion};
use crate::Topic;

/// Holds operational settings and components for managing Kafka partitions.
///
/// This structure provides methods to handle partition assignments and
/// revocations through Kafka's rebalance callbacks.
pub struct Context<T> {
    buffer_size: usize,
    max_uncommitted: usize,
    max_enqueued_per_key: usize,
    shutdown_timeout: Option<Duration>,
    message_handler: T,
    watermark_version: Arc<WatermarkVersion>,
    managers: Arc<Managers>,
}

impl<T> Context<T> {
    /// Creates a new `Context` with provided consumer configuration and
    /// dependencies.
    ///
    /// This method is critical for initializing the management of partition
    /// assignments and revocations.
    ///
    /// # Arguments
    ///
    /// * `config` - Consumer configuration settings such as buffer sizes and
    ///   timeouts.
    /// * `message_handler` - Handler responsible for message processing.
    /// * `watermark_version` - Shared state for tracking watermark versions.
    /// * `managers` - Central storage for managing `PartitionManager`
    ///   instances.
    ///
    /// # Returns
    ///
    /// A new `Context` instance initialized with the given parameters.
    pub fn new(
        config: &ConsumerConfiguration,
        message_handler: T,
        watermark_version: Arc<WatermarkVersion>,
        managers: Arc<Managers>,
    ) -> Self {
        Self {
            buffer_size: config.max_uncommitted,
            max_uncommitted: config.max_uncommitted,
            max_enqueued_per_key: config.max_enqueued_per_key,
            shutdown_timeout: config.partition_shutdown_timeout,
            message_handler,
            watermark_version,
            managers,
        }
    }
}

impl<T> ClientContext for Context<T> where T: Send + Sync {}

impl<T> ConsumerContext for Context<T>
where
    T: MessageHandler + Clone + Send + Sync + 'static,
{
    /// Responds to Kafka's partition assignment events.
    ///
    /// This method initializes `PartitionManager` instances for newly assigned
    /// partitions and handles partition revocations.
    ///
    /// # Arguments
    ///
    /// * `consumer` - The base consumer instance.
    /// * `rebalance` - Details about the rebalance event from Kafka.
    fn pre_rebalance(&self, consumer: &BaseConsumer<Self>, rebalance: &Rebalance) {
        match rebalance {
            Rebalance::Assign(partitions) => {
                // Handle empty partition assignments
                if partitions.count() == 0 {
                    return;
                }

                for element in partitions.elements() {
                    let topic = Topic::from(element.topic());
                    let partition = element.partition();
                    info!("topic {topic} partition {partition} assigned");

                    let mut managers = self.managers.lock();

                    // Check if the partition is already assigned
                    let Entry::Vacant(vacant) = managers.entry((topic, partition)) else {
                        warn!("topic {topic} partition {partition} was already assigned");
                        continue;
                    };

                    // Create and insert a new PartitionManager
                    let manager = PartitionManager::new(
                        element.partition(),
                        self.message_handler.clone(),
                        self.buffer_size,
                        self.max_uncommitted,
                        self.max_enqueued_per_key,
                        self.shutdown_timeout,
                        self.watermark_version.clone(),
                    );

                    vacant.insert(manager);
                }
            }
            Rebalance::Revoke(partitions) => {
                let count = partitions.count();
                // Handle empty partition revocations
                if count == 0 {
                    return;
                }

                // Prepare for concurrent partition shutdown
                let shutdown_futures = FuturesUnordered::new();
                let list = Arc::new(Mutex::new(TopicPartitionList::with_capacity(count)));

                for element in partitions.elements() {
                    let topic = Topic::from(element.topic());
                    let partition = element.partition();
                    info!("topic {topic} partition {partition} revoked");

                    // Remove the PartitionManager for the revoked partition
                    let Some(manager) = self.managers.lock().remove(&(topic, partition)) else {
                        error!("cannot revoke topic {topic} partition {partition}; not assigned");
                        continue;
                    };

                    // Prepare shutdown future for the partition
                    let list = list.clone();
                    shutdown_futures.push(async move {
                        let Some(offset) = manager.shutdown().await else {
                            return;
                        };

                        let next_offset = Offset::Offset(offset + 1);
                        let mut list = list.lock();

                        // Add the next offset to the commit list
                        if let Err(error) =
                            list.add_partition_offset(&topic, partition, next_offset)
                        {
                            error!("failed to add offset to commit list: {error:#}");
                        }
                    });
                }

                // Wait for all shutdown tasks to complete
                Handle::current().block_on(shutdown_futures.for_each(|()| ready(())));

                let list = list.lock();
                if list.count() == 0 {
                    return;
                }

                // Commit final offsets
                debug!("committing {list:?}");
                if let Err(error) = consumer.commit(&list, CommitMode::Async) {
                    error!("failed to commit offsets before rebalance: {error:#}");
                }
                debug!("final offsets committed");
            }
            Rebalance::Error(_) => {}
        }
    }
}

//! Provides functionality for extracting metadata from Kafka messages.
//! This module includes a custom extractor that implements the `Extractor`
//! trait from the `opentelemetry` crate, facilitating the extraction of tracing
//! headers from Kafka message headers for distributed tracing purposes.

use std::str;

use opentelemetry::propagation::Extractor;
use rdkafka::message::{BorrowedMessage, Headers};
use rdkafka::Message;

/// A wrapper around a Kafka `BorrowedMessage` that implements the `Extractor`
/// trait, enabling the extraction of trace context information from the message
/// headers.
pub struct MessageExtractor<'a>(&'a BorrowedMessage<'a>);

impl<'a> MessageExtractor<'a> {
    /// Creates a new `MessageExtractor` for the specified Kafka message.
    ///
    /// # Arguments
    /// * `message` - A reference to the borrowed Kafka message from which
    ///   headers are extracted.
    ///
    /// # Returns
    /// A new instance of `MessageExtractor`.
    pub fn new(message: &'a BorrowedMessage<'a>) -> Self {
        Self(message)
    }
}

impl<'a> Extractor for MessageExtractor<'a> {
    /// Retrieves the value of a header associated with the given key.
    ///
    /// # Arguments
    /// * `key` - The key of the header to retrieve.
    ///
    /// # Returns
    /// An option containing the header value if found, otherwise `None`.
    fn get(&self, key: &str) -> Option<&str> {
        self.0
            .headers()?
            .iter()
            .find_map(|header| (header.key == key).then_some(header.key))
    }

    /// Returns a collection of all header keys present in the Kafka message.
    ///
    /// # Returns
    /// A vector of header keys if headers are present; otherwise, an empty
    /// vector.
    fn keys(&self) -> Vec<&str> {
        let Some(headers) = self.0.headers() else {
            return vec![];
        };

        headers.iter().map(|header| header.key).collect()
    }
}

//! Provides core functionality for handling consumer messages within a
//! Kafka message processing system. This module defines structures for
//! managing message contexts and for defining the behavior of consumer
//! messages, including tracking shutdown signals and committing messages after
//! processing.

use educe::Educe;
use tokio::sync::watch::Receiver;
use tracing::{debug, Span};

use crate::consumer::partition::offsets::UncommittedOffset;
use crate::consumer::Keyed;
use crate::{Key, Offset, Partition, Payload, Topic};

/// Represents the context for a message within a consumer, handling shutdown
/// notifications.
#[derive(Educe)]
#[educe(Debug)]
pub struct MessageContext {
    shutdown_rx: Receiver<bool>,
}

impl MessageContext {
    /// Creates a new message context with a receiver for shutdown signals.
    ///
    /// # Arguments
    /// * `shutdown_rx` - A receiver for the shutdown signal.
    pub(crate) fn new(shutdown_rx: Receiver<bool>) -> Self {
        Self { shutdown_rx }
    }

    /// Waits asynchronously for a shutdown signal before proceeding.
    pub async fn wait_for_shutdown(&mut self) {
        let _ = self.shutdown_rx.wait_for(|&is_shutdown| is_shutdown).await;
    }
}

/// Represents a message consumed from a topic with associated metadata and
/// state for committing.
#[derive(Educe)]
#[educe(Debug)]
pub struct ConsumerMessage {
    topic: Topic,
    partition: Partition,
    offset: Offset,
    key: Key,

    #[educe(Debug(ignore))]
    payload: Payload,

    #[educe(Debug(ignore))]
    span: Span,

    #[educe(Debug(ignore))]
    uncommitted_offset: UncommittedOffset,
}

impl ConsumerMessage {
    /// Returns a reference to the message's topic.
    #[must_use]
    pub fn topic(&self) -> &'static str {
        self.topic.as_ref()
    }

    /// Returns the partition of the message.
    #[must_use]
    pub fn partition(&self) -> Partition {
        self.partition
    }

    /// Returns the offset of the message.
    #[must_use]
    pub fn offset(&self) -> Offset {
        self.offset
    }

    /// Returns a reference to the message's payload.
    #[must_use]
    pub fn payload(&self) -> &Payload {
        &self.payload
    }

    /// Returns a reference to the associated span for tracing.
    #[must_use]
    pub fn span(&self) -> &Span {
        &self.span
    }

    /// Take ownership of the key, payload, and uncommitted offset.
    #[must_use]
    pub fn into_inner(self) -> (Key, Payload, UncommittedOffset) {
        (self.key, self.payload, self.uncommitted_offset)
    }

    /// Commits the message, marking its offset as processed.
    pub fn commit(self) {
        debug!(%self.topic, %self.partition, %self.key, %self.offset, "committing message");
        self.uncommitted_offset.commit();
    }
}

impl Keyed for ConsumerMessage {
    type Key = Key;

    /// Returns a reference to the message's key.
    fn key(&self) -> &Self::Key {
        &self.key
    }
}

/// Represents a message that is not yet being tracked for offset watermarks.
#[derive(Educe)]
#[educe(Debug)]
pub(crate) struct UntrackedMessage {
    pub(crate) topic: Topic,
    pub(crate) partition: Partition,
    pub(crate) offset: Offset,
    pub(crate) key: Key,

    #[educe(Debug(ignore))]
    pub(crate) payload: Payload,

    #[educe(Debug(ignore))]
    pub(crate) span: Span,
}

impl UntrackedMessage {
    /// Converts an `UntrackedMessage` into a `ConsumerMessage` by adding
    /// uncommitted offset tracking.
    ///
    /// # Arguments
    /// * `uncommitted_offset` - The uncommitted offset to be associated with
    ///   the message.
    pub(crate) fn into_consumer_message(
        self,
        uncommitted_offset: UncommittedOffset,
    ) -> ConsumerMessage {
        ConsumerMessage {
            topic: self.topic,
            partition: self.partition,
            offset: self.offset,
            key: self.key,
            payload: self.payload,
            span: self.span,
            uncommitted_offset,
        }
    }
}

impl Keyed for UntrackedMessage {
    type Key = Key;

    /// Returns a reference to the message's key.
    fn key(&self) -> &Self::Key {
        &self.key
    }
}

//! Kafka consumer implementation for high-level message consumption and
//! processing.
//!
//! This module provides a robust abstraction for consuming messages from Kafka
//! topics, handling complex operations such as:
//!
//! - Offset management: Tracking and committing message offsets to ensure
//!   at-least-once message processing semantics.
//! - Consumer group coordination: Participating in consumer groups for load
//!   balancing across multiple consumer instances.
//! - Message deserialization: Converting raw Kafka messages into typed Rust
//!   structures for easier processing.
//! - Backpressure management: Limiting the number of in-flight messages to
//!   prevent overwhelming downstream systems.
//! - Error handling and recovery: Gracefully handling various error scenarios
//!   and attempting to recover when possible.
//! - Distributed tracing: Integrating with OpenTelemetry for tracing message
//!   flow across distributed systems.
//!
//! The module consists of several submodules:
//!
//! - `context`: Manages Kafka partition assignments and revocations.
//! - `extractor`: Extracts metadata from Kafka messages for distributed
//!   tracing.
//! - `message`: Defines structures for message contexts and consumer messages.
//! - `partition`: Handles partition-specific operations and state management.
//! - `poll`: Implements the core message polling and processing loop.
//!
//! Users should primarily interact with the [`ProsodyConsumer`] struct,
//! configured via [`ConsumerConfiguration`]. Custom message processing logic is
//! defined by implementing the [`MessageHandler`] trait.

use std::fmt::{Debug, Display};
use std::future::Future;
use std::io;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use std::sync::Arc;
use std::time::Duration;

use ahash::HashMap;
use crossbeam_utils::CachePadded;
use derive_builder::Builder;
use educe::Educe;
use futures::executor::block_on;
use parking_lot::Mutex;
use rdkafka::config::RDKafkaLogLevel;
use rdkafka::consumer::{BaseConsumer, Consumer};
use rdkafka::error::KafkaError;
use rdkafka::ClientConfig;
use thiserror::Error;
use tokio::task::{spawn_blocking, JoinHandle};
use tracing::error;
use validator::{Validate, ValidationErrors};
use whoami::fallible::hostname;

use crate::consumer::context::Context;
use crate::consumer::message::{ConsumerMessage, MessageContext};
use crate::consumer::partition::PartitionManager;
use crate::consumer::poll::poll;
use crate::util::{
    from_duration_env_with_fallback, from_env, from_env_with_fallback,
    from_option_duration_env_with_fallback, from_vec_env,
};
use crate::{Partition, Topic};

mod context;
mod extractor;
pub mod message;
mod partition;
mod poll;

/// Atomic counter for tracking changes in partition watermarks.
///
/// Used to efficiently notify the poll loop when offsets should be committed.
type WatermarkVersion = CachePadded<AtomicUsize>;

/// Thread-safe storage for partition managers.
///
/// Maps topic-partition pairs to their respective [`PartitionManager`]s.
type Managers = Mutex<HashMap<(Topic, Partition), PartitionManager>>;

/// Defines a type with an associated key.
pub trait Keyed {
    /// The type of the key.
    type Key;

    /// Retrieves the key of the item.
    ///
    /// # Returns
    ///
    /// A reference to the key.
    fn key(&self) -> &Self::Key;
}

/// Defines the behavior for handling consumed Kafka messages.
pub trait MessageHandler {
    /// The error type returned by the handler.
    type Error: Display;

    /// Processes a consumed message.
    ///
    /// # Arguments
    ///
    /// * `context` - Mutable reference to the message context.
    /// * `message` - The consumed message.
    ///
    /// # Returns
    ///
    /// A future that resolves to a Result indicating success or failure of
    /// message handling.
    fn handle(
        &self,
        context: &mut MessageContext,
        message: ConsumerMessage,
    ) -> impl Future<Output = Result<(), Self::Error>> + Send;
}

/// Configuration for the Kafka consumer.
///
/// This struct holds all the necessary configuration options for creating a
/// Kafka consumer. It uses the Builder pattern for flexible initialization and
/// supports loading values from environment variables.
#[derive(Builder, Clone, Validate)]
pub struct ConsumerConfiguration {
    /// List of Kafka bootstrap servers.
    ///
    /// Environment variable: `PROSODY_BOOTSTRAP_SERVERS`
    /// Default: None (must be specified)
    ///
    /// At least one server must be specified.
    #[builder(default = "from_vec_env(\"PROSODY_BOOTSTRAP_SERVERS\")?", setter(into))]
    #[validate(length(min = 1_u64))]
    pub bootstrap_servers: Vec<String>,

    /// Consumer group ID.
    ///
    /// Environment variable: `PROSODY_GROUP_ID`
    /// Default: None (must be specified)
    ///
    /// The group ID must be a non-empty string and should be unique for each
    /// logically separate consumer application. Consumers with the same group
    /// ID will form a consumer group and share the load of consuming topics.
    #[builder(default = "from_env(\"PROSODY_GROUP_ID\")?", setter(into))]
    #[validate(length(min = 1_u64))]
    pub group_id: String,

    /// List of topics to subscribe to.
    ///
    /// Environment variable: `PROSODY_SUBSCRIBED_TOPICS`
    /// Default: None (must be specified)
    ///
    /// At least one topic must be specified.
    #[builder(default = "from_vec_env(\"PROSODY_SUBSCRIBED_TOPICS\")?", setter(into))]
    #[validate(length(min = 1_u64))]
    pub subscribed_topics: Vec<String>,

    /// Maximum number of uncommitted messages.
    ///
    /// Environment variable: `PROSODY_MAX_UNCOMMITTED`
    /// Default: 32
    #[builder(
        default = "from_env_with_fallback(\"PROSODY_MAX_UNCOMMITTED\", 32)?",
        setter(into)
    )]
    #[validate(range(min = 1_usize))]
    pub max_uncommitted: usize,

    /// Maximum number of enqueued messages per key.
    ///
    /// Environment variable: `PROSODY_MAX_ENQUEUED_PER_KEY`
    /// Default: 8
    #[builder(
        default = "from_env_with_fallback(\"PROSODY_MAX_ENQUEUED_PER_KEY\", 8)?",
        setter(into)
    )]
    #[validate(range(min = 1_usize))]
    pub max_enqueued_per_key: usize,

    /// Timeout for partition shutdown.
    ///
    /// Environment variable: `PROSODY_PARTITION_SHUTDOWN_TIMEOUT`
    /// Default: 5 seconds
    ///
    /// If set to None (or if the environment variable is set to "none"), the
    /// partition will immediately be shutdown without waiting for in-flight
    /// tasks to complete. As these tasks will not be committed, they will be
    /// retried when the partition is rebalanced to a new node. This may be
    /// appropriate when performing user-facing processing where delays due to
    /// rebalancing must be minimized.
    #[builder(
        default = "from_option_duration_env_with_fallback(\"PROSODY_PARTITION_SHUTDOWN_TIMEOUT\", \
                   Duration::from_secs(5))?",
        setter(into)
    )]
    pub partition_shutdown_timeout: Option<Duration>,

    /// Interval between poll operations.
    ///
    /// Environment variable: `PROSODY_POLL_INTERVAL`
    /// Default: 100 milliseconds
    #[builder(
        default = "from_duration_env_with_fallback(\"PROSODY_POLL_INTERVAL\", \
                   Duration::from_millis(100))?",
        setter(into)
    )]
    pub poll_interval: Duration,

    /// Interval between commit operations.
    ///
    /// Environment variable: `PROSODY_COMMIT_INTERVAL`
    /// Default: 1 second
    #[builder(
        default = "from_duration_env_with_fallback(\"PROSODY_COMMIT_INTERVAL\", \
                   Duration::from_secs(1))?",
        setter(into)
    )]
    pub commit_interval: Duration,

    /// Use a mock consumer for testing purposes.
    ///
    /// Environment variable: `PROSODY_MOCK`
    /// Default: false
    #[builder(
        default = "from_env_with_fallback(\"PROSODY_MOCK\", false)?",
        setter(into)
    )]
    pub mock: bool,
}

impl ConsumerConfiguration {
    /// Creates a new `ConsumerConfigurationBuilder`.
    ///
    /// This method is a convenient way to start building a
    /// `ConsumerConfiguration`.
    ///
    /// # Returns
    ///
    /// A default `ConsumerConfigurationBuilder` instance.
    #[must_use]
    pub fn builder() -> ConsumerConfigurationBuilder {
        ConsumerConfigurationBuilder::default()
    }
}

/// High-level Kafka consumer implementation.
#[derive(Clone, Educe)]
#[educe(Debug)]
pub struct ProsodyConsumer {
    #[educe(Debug(ignore))]
    shutdown: Arc<AtomicBool>,

    #[educe(Debug(ignore))]
    handle: Arc<Mutex<Option<JoinHandle<()>>>>,
}

impl ProsodyConsumer {
    /// Creates a new `ProsodyConsumer` instance.
    ///
    /// # Arguments
    ///
    /// * `config` - The consumer configuration.
    /// * `message_handler` - The message handler implementation.
    ///
    /// # Returns
    ///
    /// A Result containing the new `ProsodyConsumer` instance or a
    /// `ConsumerError`.
    ///
    /// # Errors
    ///
    /// Returns a `ConsumerError` if:
    /// - The configuration is invalid
    /// - The hostname cannot be retrieved
    /// - The Kafka consumer cannot be created
    /// - The consumer fails to subscribe to the specified topics
    pub fn new<T>(config: ConsumerConfiguration, message_handler: T) -> Result<Self, ConsumerError>
    where
        T: MessageHandler + Clone + Send + Sync + 'static,
    {
        // Validate the configuration
        config.validate()?;

        // Initialize shared state
        let watermark_version: Arc<WatermarkVersion> = Arc::default();
        let managers: Arc<Managers> = Arc::default();
        let shutdown: Arc<AtomicBool> = Arc::default();

        // Create the consumer context with the message handler and shared state
        let context = Context::new(
            &config,
            message_handler,
            watermark_version.clone(),
            managers.clone(),
        );

        // Configure and create the Kafka consumer
        let mut client_config = ClientConfig::new();
        client_config
            .set("bootstrap.servers", config.bootstrap_servers.join(","))
            .set("client.id", hostname()?)
            .set("group.id", config.group_id)
            .set("enable.auto.commit", "false")
            .set("enable.auto.offset.store", "false")
            .set("auto.offset.reset", "earliest")
            .set("partition.assignment.strategy", "cooperative-sticky")
            .set_log_level(RDKafkaLogLevel::Error);

        // Set up mock broker if configured
        if config.mock {
            client_config.set("test.mock.num.brokers", "3");
        }

        let consumer: BaseConsumer<_> = client_config.create_with_context(context)?;

        // Subscribe to the specified topics
        let topics: Vec<&str> = config
            .subscribed_topics
            .iter()
            .map(String::as_str)
            .collect();

        consumer.subscribe(&topics)?;

        // Spawn a blocking task to continuously poll for messages
        let cloned_shutdown = shutdown.clone();
        let handle = Arc::new(Mutex::new(Some(spawn_blocking(move || {
            poll(
                config.poll_interval,
                config.commit_interval,
                &consumer,
                &watermark_version,
                &managers,
                &cloned_shutdown,
            );
        }))));

        Ok(Self { shutdown, handle })
    }

    /// Initiates a graceful shutdown of the Kafka consumer.
    ///
    /// This method signals the consumer to stop and waits for the polling task
    /// to complete.
    pub async fn shutdown(mut self) {
        self.execute_shutdown().await;
    }

    /// Execute a consumer shutdown.
    ///
    /// Used by both the public shutdown method and the drop handler.
    async fn execute_shutdown(&mut self) {
        // Signal the consumer to shut down
        self.shutdown.store(true, Ordering::Relaxed);

        // Attempt to take the handle from the mutex
        let Some(handle) = self.handle.lock().take() else {
            return;
        };

        // Wait for the polling task to complete
        if let Err(error) = handle.await {
            error!("consumer shutdown failed: {error:#}");
        }
    }
}

impl Drop for ProsodyConsumer {
    fn drop(&mut self) {
        block_on(self.execute_shutdown());
    }
}

/// Errors that can occur during consumer operations.
#[derive(Debug, Error)]
#[non_exhaustive]
pub enum ConsumerError {
    /// Indicates invalid consumer configuration.
    #[error("invalid consumer configuration: {0:#}")]
    Configuration(#[from] ValidationErrors),

    /// Indicates a failure to retrieve the hostname.
    #[error("failed to retrieve hostname: {0:#}")]
    Hostname(#[from] io::Error),

    /// Indicates a Kafka operation failure.
    #[error("Kafka operation failed: {0:#}")]
    Kafka(#[from] KafkaError),
}

//! Provides the `KeyManager` for managing and processing messages keyed by hash
//! values.

use std::collections::hash_map::Entry;
use std::collections::VecDeque;
use std::future::Future;
use std::hash::Hash;
use std::time::Duration;

use ahash::RandomState;
use futures::stream::FuturesUnordered;
use futures::{pin_mut, Stream, StreamExt};
use nohash_hasher::{IntMap, IntSet};
use tokio::select;
use tokio::sync::watch::{channel, Receiver, Sender};
use tokio::time::sleep;
use tracing::warn;

use crate::consumer::partition::util::WithValue;
use crate::consumer::Keyed;

#[cfg(test)]
mod test;

type HashValue = u64;

/// Manages and processes messages keyed by hash values, ensuring concurrent
/// processing constraints within the same thread.
///
/// This manager tracks the state of each key and manages a queue of messages
/// awaiting processing in a single thread, using a combination of
/// `FuturesUnordered` to execute and manage message processing concurrently. It
/// maintains several internal states like executing tasks, busy keys,
/// and queued messages, ensuring no more than the specified number of messages
/// per key are processed concurrently.
///
/// # Fields
/// - `max_enqueued_per_key`: Maximum number of messages that can be enqueued
///   per key before being processed.
/// - `process`: The processing function applied to each message.
/// - `executing`: Active futures of messages being processed.
/// - `busy`: Set of keys currently being processed.
/// - `enqueued`: Messages waiting to be processed, keyed by hash values.
/// - `hash_state`: State of the random hash algorithm used for key management.
/// - `shutdown_tx`: Sender for the shutdown signal.
/// - `shutdown_rx`: Receiver for the shutdown signal.
pub struct KeyManager<M, F, Fut> {
    max_enqueued_per_key: usize,
    process: F,
    executing: FuturesUnordered<WithValue<HashValue, Fut>>,
    busy: IntSet<HashValue>,
    enqueued: IntMap<HashValue, VecDeque<M>>,
    hash_state: RandomState,
    shutdown_tx: Sender<bool>,
    shutdown_rx: Receiver<bool>,
}

impl<M, F, Fut> KeyManager<M, F, Fut> {
    /// Creates a new `KeyManager` instance with specified processing function
    /// and constraints, ensuring that all keys are processed in the same
    /// thread.
    ///
    /// # Arguments
    /// - `process`: A function that defines how each message is processed.
    /// - `max_enqueued_per_key`: The maximum number of messages allowed per key
    ///   before blocking further enqueue.
    ///
    /// # Returns
    /// Returns a new instance of `KeyManager`.
    ///
    /// # Panics
    /// Panics if `max_enqueued_per_key` is zero, as it would prevent any
    /// message processing.
    pub fn new(process: F, max_enqueued_per_key: usize) -> Self {
        debug_assert!(
            max_enqueued_per_key > 0,
            "max_enqueued_per_key cannot be zero"
        );
        let (shutdown_tx, shutdown_rx) = channel(false);

        Self {
            max_enqueued_per_key,
            process,
            executing: FuturesUnordered::default(),
            busy: IntSet::default(),
            enqueued: IntMap::default(),
            hash_state: RandomState::default(),
            shutdown_tx,
            shutdown_rx,
        }
    }

    /// Processes incoming messages from a stream until shutdown.
    ///
    /// # Arguments
    ///
    /// * `messages` - Stream of incoming messages.
    /// * `shutdown_timeout` - Optional duration to wait before forcefully
    ///   shutting down.
    ///
    /// # Errors
    ///
    /// This function will return an error if the processing function returns an
    /// error.
    pub async fn process_messages<S>(mut self, messages: S, shutdown_timeout: Option<Duration>)
    where
        S: Stream<Item = M>,
        M: Keyed,
        M::Key: Hash,
        F: FnMut(M, Receiver<bool>) -> Fut,
        Fut: Future,
    {
        pin_mut!(messages);

        loop {
            select! {
                biased;

                // Process the next available message from the executing queue.
                Some(hash_value) = self.executing.next() => {
                    self.handle_completion(hash_value);
                }

                // Fetch the next message from the stream and handle it.
                maybe_message = messages.next() => match maybe_message {
                    None => break,
                    Some(message) => self.handle_message(message).await,
                },
            }
        }

        // Shutdown handling: proceed if a timeout is specified, otherwise immediately
        // return.
        let Some(timeout) = shutdown_timeout else {
            let count = self.executing.len();
            if count > 0 {
                warn!("shutting down with {count} tasks in progress");
            };

            return;
        };

        // Send a shutdown signal and create the shutdown deadline future.
        let _ = self.shutdown_tx.send(true);
        let deadline = sleep(timeout);
        pin_mut!(deadline);

        loop {
            select! {
                biased;

                // Exit if the shutdown deadline is reached.
                () = &mut deadline => {
                    let count = self.executing.len();
                    warn!("shutdown timeout reached with {count} tasks in progress");
                    break;
                }

                // Continue processing remaining tasks.
                maybe_hash_value = self.executing.next() => {
                    match maybe_hash_value {
                        None => break,
                        Some(hash_value) => self.handle_completion(hash_value),
                    };
                }
            }
        }
    }

    /// Handles a new incoming message by determining its hash value and either
    /// queuing or directly processing it based on the current system load
    /// and key status.
    ///
    /// This function is a primary entry point for messages into the
    /// `KeyManager`. It computes the hash value for the message, checks the
    /// state of the key (busy or not), and decides whether to enqueue the
    /// message for later processing or to process it immediately.
    ///
    /// # Arguments
    /// - `message`: M - The message to be handled.
    async fn handle_message(&mut self, message: M)
    where
        M: Keyed,
        M::Key: Hash,
        F: FnMut(M, Receiver<bool>) -> Fut,
        Fut: Future,
    {
        // Compute a unique hash value for the message's key
        let key = message.key();
        let hash_value = self.hash_state.hash_one(key);

        // Decide whether to enqueue the message or process it immediately based on
        // key's current status
        if self.busy.contains(&hash_value) {
            self.enqueue_message(message, hash_value).await;
        } else {
            self.process_message(message, hash_value);
        }
    }

    /// Handles the removal of a key from the busy set after message processing
    /// completes.
    ///
    /// This method checks for remaining messages in the queue for the completed
    /// key and schedules them if the key is not marked busy.
    ///
    /// # Arguments
    ///
    /// `hash_value`: `HashValue` - The hash value of the completed message.
    fn handle_completion(&mut self, hash_value: HashValue)
    where
        F: FnMut(M, Receiver<bool>) -> Fut,
    {
        // Remove the completed message's hash value from the busy set
        self.busy.remove(&hash_value);

        // Check for remaining messages and process the next one if available
        let Entry::Occupied(mut occupied) = self.enqueued.entry(hash_value) else {
            return;
        };

        let Some(message) = occupied.get_mut().pop_front() else {
            occupied.remove();
            return;
        };

        self.process_message(message, hash_value);
    }

    /// Enqueues a message associated with a specific hash value into the
    /// waiting queue if the key is currently busy, otherwise it starts
    /// processing the message directly.
    ///
    /// This method is used to manage the queuing of messages for keys that are
    /// currently unable to accept new messages for processing due to
    /// concurrency limits. It ensures that messages are from dropped and
    /// are handled in a first-come, first-served basis per key.
    ///
    /// # Arguments
    /// - `message`: M - The message to be enqueued.
    /// - `hash_value`: `HashValue` - The hash value associated with the message
    ///   to manage keying and load distribution.
    async fn enqueue_message(&mut self, message: M, hash_value: HashValue)
    where
        F: FnMut(M, Receiver<bool>) -> Fut,
        Fut: Future,
    {
        // Determine the current queue length for the hash value
        let queue_len = self
            .enqueued
            .get(&hash_value)
            .map(VecDeque::len)
            .unwrap_or_default();

        // Wait until space is available in the queue if it's full
        if queue_len >= self.max_enqueued_per_key {
            while let Some(value) = self.executing.next().await {
                self.handle_completion(value);

                if value == hash_value {
                    break;
                }
            }
        }

        // Add the message to the queue for later processing
        self.enqueued
            .entry(hash_value)
            .or_default()
            .push_back(message);
    }

    /// Enqueues a message for processing or directly processes it if the key is
    /// not currently busy.
    ///
    /// This method manages the lifecycle of a message from reception to queuing
    /// or direct processing, based on the current load and state of the
    /// related key.
    ///
    /// # Arguments
    ///
    /// `message`: M - The message to process.
    /// `hash_value`: `HashValue` - Hash value used to key and manage the
    /// message.
    fn process_message(&mut self, message: M, hash_value: HashValue)
    where
        F: FnMut(M, Receiver<bool>) -> Fut,
    {
        // Create a future for processing the message
        let future = WithValue::new(
            hash_value,
            (self.process)(message, self.shutdown_rx.clone()),
        );

        // Mark the hash value as busy and add the future to the executing queue
        self.busy.insert(hash_value);
        self.executing.push(future);
    }
}

//! Unit tests for the `KeyManager` struct in the consumer partition keyed
//! module.
//!
//! This module contains QuickCheck-based property tests to verify the correct
//! functioning of the `KeyManager`, focusing on concurrent execution prevention
//! and complete message processing.

use std::cmp::max;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::Duration;

use ahash::HashMapExt;
use futures::stream::iter;
use quickcheck::{Arbitrary, Gen, TestResult};
use quickcheck_macros::quickcheck;
use scc::{HashMap, HashSet};
use tokio::runtime::Builder;
use tokio::sync::watch;
use tokio::time::sleep;

use crate::consumer::partition::keyed::KeyManager;
use crate::consumer::Keyed;

/// Represents a sequence of messages with keys and values for testing.
#[derive(Clone, Debug)]
struct Messages(Vec<(u8, u16)>);

/// A simple wrapper for a vector of u8 values used in `QuickCheck` tests.
#[derive(Clone, Debug)]
struct SimpleMessages(Vec<u8>);

/// Verifies that KeyManager prevents concurrent execution of messages with the
/// same key.
///
/// # Arguments
/// * `messages` - A `SimpleMessages` instance containing the test messages.
/// * `max_enqueued` - The maximum number of messages to enqueue per key.
#[quickcheck]
fn prevents_concurrent_key_execution(messages: SimpleMessages, max_enqueued: u8) -> TestResult {
    let Ok(runtime) = Builder::new_multi_thread().enable_time().build() else {
        return TestResult::error("failed to initialize runtime");
    };

    runtime.block_on(prevents_concurrent_key_execution_impl(
        messages,
        max_enqueued,
    ))
}

/// Verifies that KeyManager processes messages for each key in order.
///
/// # Arguments
/// * `messages` - A `SimpleMessages` instance containing the test messages.
/// * `max_enqueued` - The maximum number of messages to enqueue per key.
#[quickcheck]
fn processes_messages_in_order(messages: Messages, max_enqueued: u8) -> TestResult {
    let Ok(runtime) = Builder::new_multi_thread().enable_time().build() else {
        return TestResult::error("failed to initialize runtime");
    };

    runtime.block_on(processes_messages_in_order_impl(messages, max_enqueued))
}

/// Implements the test for preventing concurrent execution of messages with the
/// same key.
///
/// # Arguments
/// * `messages` - A `SimpleMessages` instance containing the test messages.
/// * `max_enqueued` - The maximum number of messages to enqueue per key.
///
/// # Returns
/// A `TestResult` indicating whether the test passed or failed.
async fn prevents_concurrent_key_execution_impl(
    SimpleMessages(messages): SimpleMessages,
    max_enqueued: u8,
) -> TestResult {
    let max_enqueued = max(max_enqueued as usize, 1);
    let failed = Arc::new(AtomicBool::new(false));
    let active_keys = Arc::new(HashSet::with_capacity(messages.len()));

    // Define the message processing function
    let process_fn = |key: u8, _: watch::Receiver<bool>| {
        let failed = failed.clone();
        let active_keys = active_keys.clone();

        async move {
            // Attempt to insert the key into the active set
            if active_keys.insert_async(key).await.is_ok() {
                // Simulate processing time
                sleep(Duration::from_micros(key.saturating_mul(100).into())).await;
                active_keys.remove_async(&key).await;
            } else {
                // If insertion fails, it means the key is already being processed
                failed.store(true, Ordering::Release);
            }
        }
    };

    // Process all messages using the KeyManager
    KeyManager::new(process_fn, max_enqueued)
        .process_messages(iter(messages), Some(Duration::from_millis(100)))
        .await;

    // Check if any concurrent execution was detected
    if failed.load(Ordering::Acquire) {
        TestResult::failed()
    } else {
        TestResult::passed()
    }
}

/// Implements the test for verifying that messages for each key are processed
/// in order.
///
/// # Arguments
/// * `messages` - A `SimpleMessages` instance containing the test messages.
/// * `max_enqueued` - The maximum number of messages to enqueue per key.
///
/// # Returns
/// A `TestResult` indicating whether the test passed or failed.
async fn processes_messages_in_order_impl(
    Messages(messages): Messages,
    max_enqueued: u8,
) -> TestResult {
    let max_enqueued = max(max_enqueued as usize, 1);
    let processed: Arc<HashMap<u8, Vec<u16>>> = Arc::new(HashMap::new());

    KeyManager::new(
        |(key, value), _: watch::Receiver<bool>| {
            let processed = processed.clone();
            async move {
                processed.entry_async(key).await.or_default().push(value);
            }
        },
        max_enqueued,
    )
    .process_messages(iter(messages.clone()), None)
    .await;

    let mut expected = ahash::HashMap::with_capacity(messages.len());
    for (key, value) in messages {
        expected.entry(key).or_insert_with(Vec::new).push(value);
    }

    for (key, expected_values) in expected {
        let Some(processed_values) = processed.get(&key) else {
            return TestResult::failed();
        };

        if processed_values.get() != &expected_values {
            return TestResult::failed();
        }
    }

    TestResult::passed()
}

impl Arbitrary for Messages {
    /// Generates an arbitrary `Messages` instance for `QuickCheck` tests.
    ///
    /// # Arguments
    /// * `g` - A mutable reference to a `Gen` instance for random generation.
    fn arbitrary(g: &mut Gen) -> Self {
        let count = g.size();
        let messages = (0..count)
            .map(|_| (u8::arbitrary(g), u16::arbitrary(g)))
            .collect();
        Self(messages)
    }
}

impl Arbitrary for SimpleMessages {
    /// Generates an arbitrary `SimpleMessages` instance for `QuickCheck` tests.
    ///
    /// # Arguments
    /// * `g` - A mutable reference to a `Gen` instance for random generation.
    fn arbitrary(g: &mut Gen) -> Self {
        let mut messages: Vec<u8> = Vec::arbitrary(g);
        for message in &mut messages {
            *message = *g.choose(&[1, 2, 3, 4]).unwrap_or(&1);
        }
        Self(messages)
    }
}

impl Keyed for (u8, u16) {
    type Key = u8;

    fn key(&self) -> &Self::Key {
        &self.0
    }
}

impl Keyed for u8 {
    type Key = u8;

    /// Returns a reference to the key, which is the u8 value itself.
    fn key(&self) -> &Self::Key {
        self
    }
}

//! Manages a partition in a consumer system, handling messages and managing
//! offsets. This module provides functionality to enqueue and process messages
//! concurrently, maintain a record of offset progression, and handle graceful
//! shutdown operations.

use std::future::ready;
use std::sync::atomic::AtomicUsize;
use std::sync::Arc;
use std::time::Duration;

use crossbeam_utils::CachePadded;
use educe::Educe;
use futures::StreamExt;
use thiserror::Error;
use tokio::spawn;
use tokio::sync::mpsc::error::{SendError, TrySendError};
use tokio::sync::mpsc::{channel, Receiver, Sender};
use tokio::sync::watch;
use tokio::task::JoinHandle;
use tokio_stream::wrappers::ReceiverStream;
use tracing::{debug, error, info_span, instrument, Instrument};

use crate::consumer::message::{MessageContext, UntrackedMessage};
use crate::consumer::partition::keyed::KeyManager;
use crate::consumer::partition::offsets::OffsetTracker;
use crate::consumer::MessageHandler;
use crate::{Offset, Partition};

mod keyed;
pub mod offsets;
mod util;

/// Manages a single partition with associated message processing and offset
/// management. It ensures message processing is queued and handled efficiently,
/// tracking the offset progress and handling partition-specific actions such as
/// shutdown.
#[derive(Educe)]
#[educe(Debug)]
pub struct PartitionManager {
    /// Identifier for this partition.
    partition: Partition,

    /// Manages offset tracking and commit states.
    #[educe(Debug(ignore))]
    offsets: OffsetTracker,

    /// Channel for sending messages to be processed.
    #[educe(Debug(ignore))]
    message_tx: Sender<UntrackedMessage>,

    /// Asynchronous handle for the message processing task.
    #[educe(Debug(ignore))]
    handle: JoinHandle<()>,
}

impl PartitionManager {
    /// Creates a new `PartitionManager` with specified configurations for
    /// message handling and offset management.
    ///
    /// # Arguments
    /// * `partition` - The partition identifier.
    /// * `message_handler` - Handler responsible for processing messages.
    /// * `buffer_size` - Capacity of the message channel.
    /// * `max_uncommitted` - Maximum number of uncommitted offsets.
    /// * `max_enqueued_per_key` - Maximum number of messages to hold per key.
    /// * `shutdown_timeout` - Optional duration to wait before forcefully
    ///   shutting down.
    /// * `watermark_version` - Shared variable to track watermark updates.
    pub fn new<T>(
        partition: Partition,
        message_handler: T,
        buffer_size: usize,
        max_uncommitted: usize,
        max_enqueued_per_key: usize,
        shutdown_timeout: Option<Duration>,
        watermark_version: Arc<CachePadded<AtomicUsize>>,
    ) -> Self
    where
        T: MessageHandler + Send + Sync + 'static,
    {
        let offsets = OffsetTracker::new(max_uncommitted, watermark_version);
        let (message_tx, message_rx) = channel(buffer_size);

        let handle = spawn(handle_messages(
            message_handler,
            offsets.clone(),
            message_rx,
            max_enqueued_per_key,
            shutdown_timeout,
        ));

        Self {
            partition,
            offsets,
            message_tx,
            handle,
        }
    }

    /// Checks if the partition can accept more messages.
    pub fn has_capacity(&self) -> bool {
        self.message_tx.capacity() > 0
    }

    /// Attempts to send a message to the partition. If the partition is full or
    /// closed, the message is returned.
    pub fn try_send(&self, message: UntrackedMessage) -> Result<(), UntrackedMessage> {
        self.message_tx
            .try_send(message)
            .map_err(|error| match error {
                TrySendError::Closed(message) | TrySendError::Full(message) => message,
            })
    }

    /// Retrieves the current watermark, indicating the progress of committed
    /// offsets.
    pub fn watermark(&self) -> Option<Offset> {
        self.offsets.watermark()
    }

    /// Initiates the shutdown of the partition, waiting for the completion of
    /// all tasks.
    #[instrument(level = "debug")]
    pub async fn shutdown(self) -> Option<Offset> {
        drop(self.message_tx);

        if let Err(error) = self.handle.await {
            error!(%self.partition, "error occurred while shutting down partition: {error:#}");
            return None;
        }

        self.offsets.shutdown().await
    }
}

/// Asynchronously handles incoming messages by processing them according to the
/// provided message handler. It uses a `KeyManager` to manage the queuing and
/// processing of messages based on keys derived from the messages, facilitating
/// concurrent processing within the constraints of maximum queue sizes per key.
///
/// # Arguments
/// * `message_handler` - The handler responsible for the business logic of
///   processing messages.
/// * `offsets` - An `OffsetTracker` managing the commitment of message offsets.
/// * `message_rx` - A receiver channel from which messages are received for
///   processing.
/// * `max_enqueued_per_key` - The maximum number of messages that can be queued
///   per key before blocking.
/// * `shutdown_timeout` - Optional timeout for how long to wait on shutdown
///   before forcefully stopping message processing.
async fn handle_messages<T>(
    message_handler: T,
    offsets: OffsetTracker,
    message_rx: Receiver<UntrackedMessage>,
    max_enqueued_per_key: usize,
    shutdown_timeout: Option<Duration>,
) where
    T: MessageHandler,
{
    let process = |received: UntrackedMessage, shutdown_rx: watch::Receiver<bool>| {
        let parent_span = received.span.clone();
        let span = info_span!(parent: &parent_span, "process-message",);

        async {
            // Attempt to take an offset for the received message, and if successful,
            // transform it into a consumer message for processing.
            let message = match offsets.take(received.offset).await {
                Ok(uncommitted_offset) => received.into_consumer_message(uncommitted_offset),
                Err(error) => {
                    error!(
                        ?received,
                        "unable to take uncommitted offset: {error:#}; discarding message"
                    );
                    return;
                }
            };

            // Handle the message using the provided message handler
            let mut context = MessageContext::new(shutdown_rx);
            if let Err(error) = message_handler.handle(&mut context, message).await {
                error!("message handler returned an error: {error:#}");
            }
        }
        .instrument(span)
    };

    // Create and run a KeyManager to manage concurrent message processing,
    // using the defined processing logic and managing shutdown timing.
    let mut highest_offset_seen = -1;
    KeyManager::new(process, max_enqueued_per_key)
        .process_messages(
            ReceiverStream::new(message_rx).filter(|message| {
                // Filter out messages with offsets we've already seen. This reduces duplicates
                // during rebalances but doesn't guarantee exactly-once processing.
                if message.offset <= highest_offset_seen {
                    debug!(
                        "filtering stale partition {} offset {}",
                        message.partition, message.offset
                    );
                    return ready(false);
                }
                // Update the highest offset seen to the current message's offset
                highest_offset_seen = message.offset;
                ready(true)
            }),
            shutdown_timeout,
        )
        .await;
}

/// Defines errors related to partition management, specifically during message
/// sending.
#[derive(Debug, Error)]
pub enum PartitionError {
    /// Error when message sending fails due to the partition being shut down.
    #[error("failed to send; partition has been shutdown")]
    Shutdown(#[from] SendError<UntrackedMessage>),
}

//! Manages and synchronizes offset handling in Kafka, allowing
//! for concurrent processing while ensuring offsets are committed in order. The
//! module provides mechanisms to reserve and commit offsets, and
//! maintains a watermark to track the latest contiguous committed offset.

use std::collections::BTreeMap;
use std::sync::atomic::{AtomicI64, AtomicUsize, Ordering};
use std::sync::Arc;

use crossbeam_utils::CachePadded;
use educe::Educe;
use parking_lot::Mutex;
use thiserror::Error;
use tokio::spawn;
use tokio::sync::mpsc::{channel, OwnedPermit, Receiver, Sender};
use tokio::task::JoinHandle;
use tracing::{debug, error, instrument, warn};

use crate::Offset;

#[cfg(test)]
mod test;

/// Manages uncommitted offsets and tracks the highest successfully committed
/// offset. Utilizes atomic operations and a mutex-guarded task handle for
/// managing background operations that update the watermark based on committed
/// offsets.
#[derive(Clone, Educe)]
#[educe(Debug)]
pub struct OffsetTracker {
    /// Channel to transmit actions related to offset management.
    #[educe(Debug(ignore))]
    action_tx: Sender<Action>,

    /// Stores the highest committed offset in an atomic variable.
    #[educe(Debug(ignore))]
    watermark: Arc<CachePadded<AtomicI64>>,

    /// Manages the background task for watermark updates.
    #[educe(Debug(ignore))]
    handle: Arc<Mutex<Option<JoinHandle<()>>>>,
}

/// Holds an offset that has been reserved but not yet committed, with
/// mechanisms to commit the offset.
#[derive(Educe)]
#[educe(Debug)]
pub struct UncommittedOffset {
    /// The specific offset that has been taken and awaits commitment.
    offset: Offset,

    /// Permit to send the offset commit message.
    #[educe(Debug(ignore))]
    permit: Option<OwnedPermit<Action>>,
}

/// Describes an operation to be performed on an offset, such as reserving or
/// committing it.
#[derive(Clone, Debug)]
struct Action {
    offset: Offset,
    operation: Operation,
}

/// Defines possible operations on offsets
#[derive(Copy, Clone, Debug, Eq, PartialEq)]
enum Operation {
    Take,
    Commit,
}

impl OffsetTracker {
    /// Initializes a new `OffsetTracker` with the specified capacity for
    /// uncommitted offsets. Spawns a background task to monitor and commit
    /// offsets, updating the watermark accordingly.
    ///
    /// # Arguments
    /// * `max_uncommitted` - Maximum number of uncommitted offsets allowed.
    /// * `watermark_version` - Shared atomic variable to track changes in the
    ///   watermark.
    pub fn new(max_uncommitted: usize, watermark_version: Arc<CachePadded<AtomicUsize>>) -> Self {
        let (action_tx, action_rx) = channel(max_uncommitted + 1);
        let watermark = Arc::new(CachePadded::new(AtomicI64::new(-1)));

        let handle = Arc::new(Mutex::new(Some(spawn(track_watermark(
            action_rx,
            watermark.clone(),
            watermark_version,
        )))));

        Self {
            action_tx,
            watermark,
            handle,
        }
    }

    /// Reserves an offset for potential future commitment. Provides an
    /// UncommittedOffset that can be committed or rolled back.
    ///
    /// # Arguments
    /// * `offset` - The offset to reserve.
    ///
    /// # Returns
    /// A Result containing either an UncommittedOffset or an
    /// OffsetTrackerError.
    ///
    /// # Errors
    /// Returns `OffsetTrackerError::Shutdown` if the system is shutting down
    /// and cannot accept new reservations.
    #[instrument(level = "debug")]
    pub async fn take(&self, offset: Offset) -> Result<UncommittedOffset, OffsetTrackerError> {
        let permit = Some(
            self.action_tx
                .clone()
                .reserve_owned()
                .await
                .map_err(|_| OffsetTrackerError::Shutdown)?,
        );

        self.action_tx
            .send(Action::take(offset))
            .await
            .map_err(|_| OffsetTrackerError::Shutdown)?;

        Ok(UncommittedOffset { offset, permit })
    }

    /// Fetches the current watermark, representing the highest committed
    /// offset, if available.
    ///
    /// # Returns
    /// An Option containing the current watermark if it is valid.
    pub fn watermark(&self) -> Option<Offset> {
        fetch_watermark(&self.watermark)
    }

    /// Shuts down the OffsetTracker, closing the action channel and awaiting
    /// the completion of the background task to ensure all pending actions
    /// are resolved.
    ///
    /// # Returns
    /// An Option containing the last known valid watermark if available.
    #[instrument(level = "debug")]
    pub async fn shutdown(self) -> Option<Offset> {
        drop(self.action_tx);
        let Some(handle) = self.handle.lock().take() else {
            warn!("offset tracker already shutdown");
            return fetch_watermark(&self.watermark);
        };

        let _ = handle.await;
        fetch_watermark(&self.watermark)
    }
}

/// Fetches the watermark from an atomic variable, ensuring it reflects
/// committed data.
///
/// # Returns
/// An Option containing the watermark if it represents a committed offset.
fn fetch_watermark(watermark: &CachePadded<AtomicI64>) -> Option<Offset> {
    let watermark = watermark.load(Ordering::Acquire);
    (watermark >= 0).then_some(watermark)
}

/// Enumerates potential errors that can occur during offset management.
#[derive(Debug, Error)]
pub enum OffsetTrackerError {
    /// Indicates a failure due to the system shutting down, preventing
    /// operation completion.
    #[error("operation failed: shutdown")]
    Shutdown,
}

impl UncommittedOffset {
    /// Commits the reserved offset, finalizing its state.
    pub fn commit(mut self) {
        let Some(permit) = self.permit.take() else {
            error!("offset {} already committed", self.offset);
            return;
        };
        permit.send(Action::commit(self.offset));
    }
}

impl Drop for UncommittedOffset {
    /// Logs a warning if an offset is dropped without being committed,
    /// indicating potential data loss.
    fn drop(&mut self) {
        let Some(_) = self.permit.take() else {
            return;
        };

        warn!(%self.offset, "offset was dropped without committing");
    }
}

impl Action {
    /// Creates a Take action for a specific offset.
    fn take(offset: Offset) -> Self {
        Self {
            offset,
            operation: Operation::Take,
        }
    }

    /// Creates a Commit action for a specific offset.
    fn commit(offset: Offset) -> Self {
        Self {
            offset,
            operation: Operation::Commit,
        }
    }
}

/// Processes actions from a receiver to update the watermark based on committed
/// offsets. This background task adjusts the watermark to reflect the highest
/// contiguous committed offset. It maintains a sorted map of offsets and
/// updates the watermark whenever it can extend the contiguous sequence of
/// committed offsets. The process continues until the action channel closes
/// during system shutdown.
///
/// # Arguments
/// * `action_rx` - Receiver for offset actions, each either reserving or
///   committing an offset.
/// * `watermark` - Shared atomic variable tracking the highest committed
///   offset.
/// * `watermark_version` - Atomic variable to track watermark updates.
async fn track_watermark(
    mut action_rx: Receiver<Action>,
    watermark: Arc<CachePadded<AtomicI64>>,
    watermark_version: Arc<CachePadded<AtomicUsize>>,
) {
    // Map to keep track of offset actions.
    let mut watermarks = BTreeMap::new();

    // Process actions from the receiver until the channel is closed.
    while let Some(action) = action_rx.recv().await {
        // Insert action into the map.
        watermarks.insert(action.offset, action.operation);

        // Initialize a placeholder for potentially updating the watermark.
        let mut new_watermark = None;

        // Attempt to update the watermark based on the lowest available offsets.
        // This loop checks each entry, advancing the watermark when contiguous
        // committed offsets are found and removing them to keep the dataset
        // minimal.
        while let Some(entry) = watermarks.first_entry() {
            // If the lowest offset in the map is committed, update the watermark.
            if *entry.get() == Operation::Commit {
                let (offset, _) = entry.remove_entry();
                new_watermark = Some(offset);
            } else {
                break;
            }
        }

        // Update the shared watermark if a new one was established.
        if let Some(new_offset) = new_watermark {
            watermark.store(new_offset, Ordering::Release);

            // Increment the version to indicate a change.
            watermark_version.fetch_add(1, Ordering::AcqRel);
        }
    }

    debug!("watermark tracking shutdown");
}

//! Unit tests for the `OffsetTracker` in the consumer partition offsets module.
//!
//! This module contains QuickCheck-based property tests to verify the correct
//! functioning of the `OffsetTracker`, focusing on watermark tracking and
//! committing.

use std::collections::BTreeMap;
use std::sync::Arc;

use ahash::{HashMap, HashMapExt, HashSet};
use quickcheck::{Arbitrary, Gen, TestResult};
use quickcheck_macros::quickcheck;
use tokio::runtime::Builder;

use crate::consumer::partition::offsets::{Action, OffsetTracker, Operation};
use crate::Offset;

/// A wrapper for a vector of Actions used in `QuickCheck` tests.
#[derive(Clone, Debug)]
struct Actions(Vec<Action>);

/// Verifies that OffsetTracker correctly tracks and commits watermarks.
///
/// # Arguments
/// * `actions` - An `Actions` instance containing the test actions.
#[quickcheck]
fn tracks_commit_watermark(actions: Actions) -> TestResult {
    let Ok(runtime) = Builder::new_multi_thread().enable_time().build() else {
        return TestResult::error("failed to initialize runtime");
    };

    runtime.block_on(tracks_commit_watermark_impl(actions))
}

/// Implements the test for verifying watermark tracking and committing.
///
/// # Arguments
/// * `actions` - An `Actions` instance containing the test actions.
///
/// # Returns
/// A `TestResult` indicating whether the test passed or failed.
async fn tracks_commit_watermark_impl(Actions(actions): Actions) -> TestResult {
    let version = Arc::default();
    let tracker = OffsetTracker::new(actions.len() + 1, version);
    let mut test_offsets = BTreeMap::default();
    let mut commits = HashMap::with_capacity(actions.len());

    // Process each action
    for action in &actions {
        match action.operation {
            Operation::Take => {
                // Take an offset from the tracker
                let commit = match tracker.take(action.offset).await {
                    Ok(offset) => offset,
                    Err(error) => return TestResult::error(format!("tracker failed: {error:#}")),
                };

                commits.insert(action.offset, commit);
                test_offsets.insert(action.offset, action.operation);
            }
            Operation::Commit => {
                // Commit an offset if it was previously taken
                if let Some(commit) = commits.remove(&action.offset) {
                    commit.commit();
                    test_offsets.insert(action.offset, action.operation);
                }
            }
        }
    }

    drop(commits);

    // Determine the expected watermark
    let expected = test_offsets
        .iter()
        .take_while(|(_, &action)| action == Operation::Commit)
        .last()
        .map(|(&offset, _)| offset);

    // Get the actual watermark from the tracker
    let actual = tracker.shutdown().await;

    // Compare expected and actual watermarks
    if expected == actual {
        TestResult::passed()
    } else {
        TestResult::error(format!("{expected:?} != {actual:?} ({test_offsets:?})"))
    }
}

impl Arbitrary for Actions {
    /// Generates an arbitrary `Actions` instance for `QuickCheck` tests.
    ///
    /// # Arguments
    /// * `g` - A mutable reference to a `Gen` instance for random generation.
    fn arbitrary(g: &mut Gen) -> Self {
        let mut offset: Offset = 0;
        let mut takes = HashSet::default();
        let mut actions = Vec::<Action>::arbitrary(g);
        let gaps: Vec<Offset> = (0..4).collect();

        for action in &mut actions {
            if takes.is_empty() || bool::arbitrary(g) {
                // Generate a Take action
                let gap = *g.choose(&gaps).unwrap_or(&0);
                offset += gap as Offset;
                action.offset = offset;
                action.operation = Operation::Take;
                takes.insert(offset);
                offset += 1;
            } else {
                // Generate a Commit action
                let possible_takes = takes.iter().copied().collect::<Vec<_>>();
                let Some(offset) = g.choose(&possible_takes) else {
                    continue;
                };

                action.offset = *offset;
                action.operation = Operation::Commit;
                takes.remove(&action.offset);
            }
        }

        Self(actions)
    }
}

impl Arbitrary for Action {
    /// Generates an arbitrary `Action` for `QuickCheck` tests.
    ///
    /// # Arguments
    /// * `g` - A mutable reference to a `Gen` instance for random generation.
    fn arbitrary(g: &mut Gen) -> Self {
        Self {
            offset: u16::arbitrary(g).into(),
            operation: Operation::arbitrary(g),
        }
    }
}

impl Arbitrary for Operation {
    /// Generates an arbitrary `Operation` for `QuickCheck` tests.
    ///
    /// # Arguments
    /// * `g` - A mutable reference to a `Gen` instance for random generation.
    fn arbitrary(g: &mut Gen) -> Self {
        if bool::arbitrary(g) {
            Operation::Take
        } else {
            Operation::Commit
        }
    }
}

//! This module provides a utility to wrap a future and a value, returning the
//! value once the future completes.
//!
//! The primary struct, `WithValue`, is designed to be used in asynchronous
//! contexts where the completion of a future should result in a predetermined
//! value being returned. This can simplify scenarios where the outcome of an
//! asynchronous operation is not the value produced by the future, but a fixed
//! value associated with the completion of the future.

use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

use pin_project::pin_project;

/// The `WithValue` struct wraps a future and a value, returning the value once
/// the future completes.
#[pin_project]
pub struct WithValue<T, F> {
    /// The value to be returned once the future completes.
    value: T,

    /// The future to be awaited.
    #[pin]
    future: F,
}

impl<T, F> WithValue<T, F> {
    /// Creates a new `WithValue` instance.
    ///
    /// # Arguments
    ///
    /// * `value` - The value to be returned once the future completes.
    /// * `future` - The future to be awaited.
    ///
    /// # Returns
    ///
    /// A new `WithValue` instance.
    pub fn new(value: T, future: F) -> Self {
        WithValue { value, future }
    }
}

impl<T, F> Future for WithValue<T, F>
where
    T: Clone,
    F: Future,
{
    type Output = T;

    /// Polls the future, returning the value once the future completes.
    ///
    /// # Arguments
    ///
    /// * `cx` - The task context to poll with.
    ///
    /// # Returns
    ///
    /// `Poll::Ready` with the value if the future completes, otherwise
    /// `Poll::Pending`.
    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        // Project the fields to handle pinning safely.
        let mut projection = self.project();

        // Poll the inner future. If it is ready, return the cloned value.
        projection
            .future
            .as_mut()
            .poll(cx)
            .map(|_| projection.value.clone())
    }
}

//! Provides functionality for polling and processing Kafka messages with
//! distributed tracing support.

use std::str;
use std::sync::atomic::{AtomicBool, Ordering};
use std::thread::sleep;
use std::time::{Duration, Instant};

use internment::Intern;
use opentelemetry::propagation::TextMapPropagator;
use rdkafka::consumer::{BaseConsumer, CommitMode, Consumer};
use rdkafka::error::KafkaError;
use rdkafka::util::Timeout;
use rdkafka::{Message, Offset, TopicPartitionList};
use thiserror::Error;
use tracing::field::Empty;
use tracing::{error, info_span, warn};
use tracing_opentelemetry::OpenTelemetrySpanExt;

use crate::consumer::context::Context;
use crate::consumer::extractor::MessageExtractor;
use crate::consumer::message::UntrackedMessage;
use crate::consumer::partition::PartitionManager;
use crate::consumer::{Managers, MessageHandler, WatermarkVersion};
use crate::propagator::new_propagator;
use crate::Key;

/// Polls messages from Kafka, processes them, and handles partition management.
///
/// # Arguments
/// - `poll_interval`: Duration to wait between polling attempts.
/// - `commit_interval`: Duration to wait between offset commits.
/// - `consumer`: Kafka consumer instance.
/// - `watermark_version`: Current watermark version for offset tracking.
/// - `managers`: Manager collection for handling partitions.
/// - `shutdown`: Atomic boolean to signal shutdown.
pub fn poll<T>(
    poll_interval: Duration,
    commit_interval: Duration,
    consumer: &BaseConsumer<Context<T>>,
    watermark_version: &WatermarkVersion,
    managers: &Managers,
    shutdown: &AtomicBool,
) where
    T: MessageHandler + Clone + Send + Sync + 'static,
{
    let propagator = new_propagator();
    let mut last_version = watermark_version.load(Ordering::Acquire);
    let mut last_commit = Instant::now();
    let mut is_paused = false;

    while !shutdown.load(Ordering::Relaxed) {
        // Periodically commit offsets and manage busy partitions
        commit_watermarks(
            &commit_interval,
            consumer,
            watermark_version,
            managers,
            &mut last_version,
            &mut last_commit,
        );

        if let Err(error) = pause_busy_partitions(&mut is_paused, consumer, managers) {
            error!("error pausing busy partitions: {error:#}; retrying");
            sleep(poll_interval);
            continue;
        }

        // Poll for new messages
        let Some(result) = consumer.poll(Timeout::After(poll_interval)) else {
            continue;
        };

        let message = match result {
            Ok(message) => message,
            Err(error) => {
                error!("error polling for message: {error:#}");
                continue;
            }
        };

        // Extract message details and create tracing span
        let topic = Intern::from(message.topic());
        let partition = message.partition();
        let offset = message.offset();

        let context = propagator.extract(&MessageExtractor::new(&message));
        let span = info_span!(
            "receive-message",
            %topic, %partition, %offset, key = Empty, payload_size = Empty
        );

        span.set_parent(context);
        let _enter = span.enter();

        // Validate message key and payload
        let Some(key_data) = message.key() else {
            error!("missing key; discarding message");
            continue;
        };

        let Some(payload_data) = message.payload() else {
            error!("missing payload; discarding message");
            continue;
        };
        span.record("payload_size", payload_data.len());

        // Parse key and payload
        let key: Key = match str::from_utf8(key_data) {
            Ok(key) => {
                span.record("key", key);
                key.into()
            }
            Err(error) => {
                error!("invalid key encoding: {error:#}; discarding message");
                continue;
            }
        };

        let payload = match serde_json::from_slice(payload_data) {
            Ok(payload) => payload,
            Err(error) => {
                error!("invalid payload: {error:#}; discarding message");
                continue;
            }
        };

        // Create UntrackedMessage and dispatch for processing
        let mut message = UntrackedMessage {
            topic,
            partition,
            offset,
            key,
            payload,
            span: span.clone(),
        };

        // Dispatch message to appropriate handler
        loop {
            match dispatch_message(message, managers) {
                Ok(()) => break,
                Err(error @ DispatchError::PartitionNotFound(_)) => {
                    warn!("failed to dispatch message: {error:#}; discarding");
                    break;
                }
                Err(DispatchError::Busy(failed)) => {
                    error!("failed to dispatch message because partition is busy; retrying");
                    message = failed;
                    sleep(poll_interval);
                }
            }
        }
    }
}

/// Commits the current offsets for all managed partitions if necessary.
///
/// # Arguments
/// - `commit_interval`: Interval between offset commits.
/// - `consumer`: Kafka consumer instance.
/// - `watermark_version`: Current watermark version for offset tracking.
/// - `managers`: Manager collection for handling partitions.
/// - `last_version`: Last committed watermark version.
/// - `last_commit`: Time of the last commit attempt.
fn commit_watermarks<T>(
    commit_interval: &Duration,
    consumer: &BaseConsumer<Context<T>>,
    watermark_version: &WatermarkVersion,
    managers: &Managers,
    last_version: &mut usize,
    last_commit: &mut Instant,
) where
    T: MessageHandler + Clone + Send + Sync + 'static,
{
    let current_version = watermark_version.load(Ordering::Acquire);
    if current_version == *last_version {
        return;
    }

    let now = Instant::now();
    if now.duration_since(*last_commit) < *commit_interval {
        return;
    }

    let mut success = true;

    // Prepare offset list for commit
    let managers = managers.lock();
    let mut list = TopicPartitionList::with_capacity(managers.len());
    for ((topic, partition), manager) in managers.iter() {
        let Some(watermark) = manager.watermark() else {
            continue;
        };

        let next_offset = Offset::Offset(watermark + 1);
        if let Err(error) = list.add_partition_offset(topic, *partition, next_offset) {
            error!(%topic, %partition, %watermark, "failed to add offset to commit list: {error:#}");
            success = false;
        }
    }

    // Commit offsets
    if let Err(error) = consumer.commit(&list, CommitMode::Async) {
        error!("failed to add commit offsets: {error:#}");
        success = false;
    }

    if success {
        *last_version = current_version;
        *last_commit = now;
    }
}

/// Pauses or resumes partitions based on their capacity status.
///
/// # Arguments
/// - `is_paused`: Indicates if any partitions are currently paused.
/// - `consumer`: Kafka consumer instance.
/// - `managers`: Manager collection for handling partitions.
///
/// # Errors
/// Returns `KafkaError` if there is an error pausing or resuming partitions.
fn pause_busy_partitions<T>(
    is_paused: &mut bool,
    consumer: &BaseConsumer<Context<T>>,
    managers: &Managers,
) -> Result<(), KafkaError>
where
    T: MessageHandler + Clone + Send + Sync + 'static,
{
    let managers = managers.lock();

    // Short circuit when all partitions have capacity to avoid allocation
    if !*is_paused && managers.values().all(PartitionManager::has_capacity) {
        return Ok(());
    }

    let mut paused = TopicPartitionList::with_capacity(managers.len());
    let mut resumed = TopicPartitionList::with_capacity(managers.len());

    // Categorize partitions as paused or resumed based on capacity
    for ((topic, partition), manager) in managers.iter() {
        if manager.has_capacity() {
            resumed.add_partition(topic.as_ref(), *partition);
        } else {
            paused.add_partition(topic.as_ref(), *partition);
        }
    }

    *is_paused = paused.count() > 0;

    // Apply pause and resume operations
    if *is_paused {
        consumer.pause(&paused)?;
    }

    if resumed.count() > 0 {
        consumer.resume(&resumed)?;
    }

    Ok(())
}

/// Dispatches a message to the appropriate partition manager.
///
/// # Arguments
/// - `message`: The message to dispatch.
/// - `managers`: Manager collection for handling partitions.
///
/// # Returns
/// Returns a `DispatchError` if dispatch fails.
fn dispatch_message(message: UntrackedMessage, managers: &Managers) -> Result<(), DispatchError> {
    let managers = managers.lock();
    let Some(manager) = managers.get(&(message.topic, message.partition)) else {
        return Err(DispatchError::PartitionNotFound(message));
    };

    let Err(message) = manager.try_send(message) else {
        return Ok(());
    };

    Err(DispatchError::Busy(message))
}

/// Errors that can occur during message dispatch.
#[derive(Debug, Error)]
enum DispatchError {
    /// Message sent to an unassigned partition.
    #[error("message sent to unassigned partition")]
    PartitionNotFound(UntrackedMessage),

    /// Partition is busy and cannot accept more messages.
    #[error("partition is busy")]
    Busy(UntrackedMessage),
}

//! A high-level Kafka client library with support for distributed tracing.
//!
//! This crate provides abstractions for interacting with Apache Kafka,
//! offering both consumer and producer implementations. It integrates
//! OpenTelemetry for distributed tracing, allowing for better observability
//! in microservice architectures.
//!
//! # Features
//!
//! - **Kafka Consumer**: Efficiently consume messages with support for offset
//!   management and consumer groups.
//! - **Kafka Producer**: Reliably produce messages with idempotent delivery.
//! - **Distributed Tracing**: Seamless integration with OpenTelemetry for
//!   enhanced observability in microservice architectures.
//! - **Configurable**: Flexible configuration through environment variables.
//! - **Asynchronous**: Built on top of Tokio for high-performance asynchronous
//!   operations.
//! - **Backpressure Management**: Intelligent partition pausing to handle
//!   processing backlogs.
//! - **Mocking Support**: Ability to use mock Kafka brokers for testing
//!   purposes.
//!
//! # Examples
//!
//! ## Producer Example
//!
//! ```rust
//! use prosody::Topic;
//! use prosody::producer::{ProducerConfiguration, ProsodyProducer};
//! use serde_json::json;
//!
//! #[tokio::main]
//! async fn main() -> Result<(), Box<dyn std::error::Error>> {
//!     let config = ProducerConfiguration::builder()
//!         .bootstrap_servers(["localhost:9092".to_owned()])
//!         .mock(true) // use mock producer for example
//!         .build()?;
//!
//!     let producer = ProsodyProducer::new(&config)?;
//!
//!     let topic: Topic = "my-topic".into();
//!     producer.send(topic, "message-key", json!({"value": "Hello, Kafka!"})).await?;
//!
//!     Ok(())
//! }
//! ```
//!
//! ## Consumer Example
//!
//! ```rust
//! use prosody::consumer::message::{ConsumerMessage, MessageContext};
//! use prosody::consumer::{ConsumerConfiguration, MessageHandler, ProsodyConsumer};
//! use prosody::Topic;
//! use std::time::Duration;
//!
//! #[derive(Clone)]
//! struct MyMessageHandler;
//!
//! impl MessageHandler for MyMessageHandler {
//!     type Error = std::io::Error;
//!
//!     async fn handle(
//!         &self,
//!         context: &mut MessageContext,
//!         message: ConsumerMessage,
//!     ) -> Result<(), Self::Error> {
//!         println!("Received: {:?}", message);
//!         message.commit();
//!         Ok(())
//!     }
//! }
//!
//! #[tokio::main]
//! async fn main() -> Result<(), Box<dyn std::error::Error>> {
//!     let config = ConsumerConfiguration::builder()
//!         .bootstrap_servers(["localhost:9092".to_owned()])
//!         .group_id("my-group")
//!         .subscribed_topics(["my-topic".to_owned()])
//!         .mock(true) // use mock consumer for example
//!         .build()?;
//!
//!     let consumer = ProsodyConsumer::new(config, MyMessageHandler)?;
//!
//!     // Run your application logic here
//!
//!     consumer.shutdown().await;
//!     Ok(())
//! }
//! ```
//!
//! # Architecture
//!
//! Prosody is designed to provide efficient and parallel processing of Kafka
//! messages while maintaining order for messages with the same key.
//!
//! ## Consumer Architecture
//!
//! The consumer in Prosody is built around the concept of partition-level
//! parallelism and key-based ordering:
//!
//! 1. **Partition-Level Parallelism**: Each Kafka partition is managed by a
//!    separate `PartitionManager`. This allows for parallel processing of
//!    messages from different partitions. The `PartitionManager` is responsible
//!    for buffering messages and tracking offsets for its assigned partition.
//!
//! 2. **Key-Based Queuing**: Within each partition, messages are further
//!    divided based on their keys. Each unique key within a partition has its
//!    own bounded queue. This ensures that messages with the same key are
//!    processed in order.
//!
//! 3. **Concurrent Processing**: Different keys can be processed concurrently,
//!    even within the same partition, allowing for high throughput. The
//!    `PartitionManager` can process messages from different key queues
//!    simultaneously.
//!
//! 4. **Ordered Processing**: Messages with the same key are processed
//!    sequentially from their respective queue, ensuring ordered processing for
//!    each key.
//!
//! 5. **Polling Mechanism**: The `ProsodyConsumer` uses a polling mechanism to
//!    efficiently fetch messages from Kafka brokers.
//!
//! 6. **Partition Pausing**: If a partition becomes backed up (i.e., its queues
//!    are full), Prosody will pause consumption from that specific partition.
//!    Other partitions continue to make progress, ensuring that a slowdown in
//!    one partition doesn't affect the entire consumer.
//!
//! ## Message Flow
//!
//! 1. The `ProsodyConsumer` polls messages from Kafka Brokers.
//! 2. Messages are dispatched to the appropriate `PartitionManager` based on
//!    their topic and partition.
//! 3. The `PartitionManager` enqueues the message in the correct key-based
//!    queue according to the message key (e.g., User ID, Product ID).
//! 4. Messages are processed sequentially from each key queue, invoking the
//!    user-provided `MessageHandler`.
//! 5. After processing, the latest processed offset for the key is updated.
//! 6. The `PartitionManager` tracks the partition's high watermark committed
//!    offset.
//! 7. The Prosody Consumer periodically commits these offsets back to Kafka,
//!    ensuring at-least-once message processing semantics.
//! 8. If a partition's queues become full, that specific partition is paused
//!    until the backlog is processed.
//!
//! Throughout this flow, OpenTelemetry is used to create and propagate
//! distributed traces, allowing for end-to-end visibility of message processing
//! across different services.
//!
//! This architecture allows Prosody to achieve high throughput by processing
//! different partitions and keys concurrently, while still maintaining strict
//! ordering for messages with the same key. It also provides backpressure
//! management by limiting the number of in-flight messages per key and
//! partition through bounded queues and selective partition pausing.
//!
//! ## Mocking Support
//!
//! Prosody provides mocking support for both consumers and producers, allowing
//! for easier testing of Kafka-dependent components. When the `mock`
//! configuration option is set to `true`, Prosody will use mock Kafka brokers
//! instead of connecting to real ones. This feature is particularly useful for
//! unit testing and continuous integration environments where setting up a real
//! Kafka cluster might be impractical.

#![allow(clippy::multiple_crate_versions)]

use internment::Intern;
use serde_json::Value;

pub mod consumer;
pub mod producer;
mod propagator;
mod util;

/// A Kafka topic name.
///
/// This type uses string interning for efficient storage and comparison of
/// topic names.
pub type Topic = Intern<str>;

/// A Kafka partition number.
pub type Partition = i32;

/// A Kafka message key.
///
/// This type uses `Box<str>` for efficient storage of variable-length strings.
pub type Key = Box<str>;

