/// Configuration for the Kafka producer.
///
/// This struct holds all the necessary configuration options for creating a
/// Kafka producer. It uses the Builder pattern for flexible initialization and
/// supports loading values from environment variables.
#[derive(Builder, Clone, Validate)]
pub struct ProducerConfiguration {
    /// List of Kafka bootstrap servers.
    ///
    /// Environment variable: `PROSODY_BOOTSTRAP_SERVERS`
    /// Default: None (must be specified)
    ///
    /// At least one server must be specified.
    #[builder(default = "from_vec_env(\"PROSODY_BOOTSTRAP_SERVERS\")?", setter(into))]
    #[validate(length(min = 1_u64))]
    pub bootstrap_servers: Vec<String>,

    /// Timeout for send operations.
    ///
    /// Environment variable: `PROSODY_SEND_TIMEOUT`
    /// Default: 1 second
    ///
    /// If set to None (or if the environment variable is set to "none"), the
    /// sender will retry indefinitely and never timeout. This may be an
    /// appropriate setting for consumers that produce to topics, as the
    /// consumed message may not be marked as complete until the message is
    /// produced.
    #[builder(
        default = "from_option_duration_env_with_fallback(\"PROSODY_SEND_TIMEOUT\", \
                   Duration::from_secs(1))?",
        setter(into)
    )]
    pub send_timeout: Option<Duration>,

    /// Use a mock producer for testing purposes.
    ///
    /// Environment variable: `PROSODY_MOCK`
    /// Default: false
    #[builder(
        default = "from_env_with_fallback(\"PROSODY_MOCK\", false)?",
        setter(into)
    )]
    pub mock: bool,
}

impl ProducerConfiguration {
    /// Creates a new `ProducerConfigurationBuilder`.
    ///
    /// This method is a convenient way to start building a
    /// `ProducerConfiguration`.
    ///
    /// # Returns
    ///
    /// A new instance of `ProducerConfigurationBuilder`.
    #[must_use]
    pub fn builder() -> ProducerConfigurationBuilder {
        ProducerConfigurationBuilder::default()
    }
}

/// High-level Kafka producer implementation.
///
/// This struct encapsulates the Kafka producer functionality, including
/// message sending and OpenTelemetry context propagation.
#[derive(Educe)]
#[educe(Debug)]
pub struct ProsodyProducer {
    /// Timeout for send operations.
    send_timeout: Timeout,

    /// Underlying Kafka producer.
    #[educe(Debug(ignore))]
    producer: FutureProducer,

    /// OpenTelemetry context propagator.
    #[educe(Debug(ignore))]
    propagator: TextMapCompositePropagator,
}

impl Clone for ProsodyProducer {
    fn clone(&self) -> Self {
        Self {
            send_timeout: self.send_timeout,
            producer: self.producer.clone(),
            propagator: new_propagator(),
        }
    }
}

impl ProsodyProducer {
    /// Creates a new `ProsodyProducer` instance.
    ///
    /// # Arguments
    ///
    /// * `config` - The producer configuration.
    ///
    /// # Returns
    ///
    /// A `Result` containing the new `ProsodyProducer` instance or a
    /// `ProducerError`.
    ///
    /// # Errors
    ///
    /// Returns a `ProducerError` if:
    /// - The configuration is invalid
    /// - The hostname cannot be retrieved
    /// - The Kafka producer cannot be created
    pub fn new(config: &ProducerConfiguration) -> Result<Self, ProducerError> {
        // Validate the configuration
        config.validate()?;

        // Set the send timeout
        let send_timeout = match config.send_timeout {
            None => Timeout::Never,
            Some(duration) => Timeout::After(duration),
        };

        // Create and configure the Kafka producer
        let mut client_config = ClientConfig::new();
        client_config
            .set("bootstrap.servers", config.bootstrap_servers.join(","))
            .set("client.id", hostname()?)
            .set("compression.codec", "lz4")
            .set("enable.idempotence", "true")
            .set_log_level(RDKafkaLogLevel::Error);

        // Set up mock broker if configured
        if config.mock {
            client_config.set("test.mock.num.brokers", "3");
        }

        Ok(Self {
            send_timeout,
            producer: client_config.create()?,
            propagator: new_propagator(),
        })
    }

    /// Sends a message to a Kafka topic.
    ///
    /// This method serializes the payload, injects OpenTelemetry context,
    /// and sends the message to the specified Kafka topic.
    ///
    /// # Arguments
    ///
    /// * `topic` - The topic to send the message to.
    /// * `key` - The message key.
    /// * `payload` - The message payload as a JSON Value.
    ///
    /// # Returns
    ///
    /// A `Result` indicating success or failure of the send operation.
    ///
    /// # Errors
    ///
    /// Returns a `ProducerError` if:
    /// - The payload cannot be serialized
    /// - The system time cannot be retrieved
    /// - The Kafka send operation fails
    pub async fn send(&self, topic: Topic, key: &str, payload: Value) -> Result<(), ProducerError> {
        // Serialize the payload
        let serialized = to_vec(&payload)?;

        // Create the record with timestamp
        let mut record = FutureRecord::to(&topic)
            .key(key)
            .payload(&serialized)
            .timestamp(SystemTime::now().duration_since(UNIX_EPOCH)?.as_millis() as i64);

        // Inject OpenTelemetry context into the record headers
        self.propagator.inject_context(
            &Span::current().context(),
            &mut RecordInjector::new(&mut record),
        );

        // Send the record
        self.producer
            .send(record, self.send_timeout)
            .await
            .map_err(|(error, _)| ProducerError::Kafka(error))?;

        Ok(())
    }
}

/// Errors that can occur during producer operations.
#[derive(Debug, Error)]
pub enum ProducerError {
    /// Indicates invalid producer configuration.
    #[error("invalid producer configuration: {0:#}")]
    Configuration(#[from] ValidationErrors),

    /// Indicates a failure to serialize the payload.
    #[error("failed to serialize payload: {0:#}")]
    Serialization(#[from] serde_json::Error),

    /// Indicates a failure to set the message timestamp.
    #[error("failed to set timestamp: {0:#}")]
    SystemTime(#[from] SystemTimeError),

    /// Indicates a failure to retrieve the hostname.
    #[error("failed to get hostname: {0:#}")]
    Hostname(#[from] io::Error),

    /// Indicates a Kafka operation failure.
    #[error("Kafka error: {0:#}")]
    Kafka(#[from] KafkaError),
}

//! Provides a composite OpenTelemetry propagator for distributed tracing.
//!
//! This module creates a `TextMapCompositePropagator` that combines
//! `BaggagePropagator` and `TraceContextPropagator`. This composite propagator
//! enables the transmission of both baggage (key-value pairs) and trace context
//! across service boundaries in distributed systems.

use opentelemetry::propagation::TextMapCompositePropagator;
use opentelemetry_sdk::propagation::{BaggagePropagator, TraceContextPropagator};

/// Creates a new composite OpenTelemetry propagator.
///
/// This function constructs a `TextMapCompositePropagator` that includes both
/// `BaggagePropagator` and `TraceContextPropagator`. The resulting propagator
/// can be used to inject and extract both baggage and trace context in
/// distributed tracing scenarios.
///
/// # Returns
///
/// A `TextMapCompositePropagator` configured with baggage and trace context
/// propagators.
pub fn new_propagator() -> TextMapCompositePropagator {
    TextMapCompositePropagator::new(vec![
        // Include BaggagePropagator for propagating key-value pairs
        Box::new(BaggagePropagator::new()),
        // Include TraceContextPropagator for propagating trace context
        Box::new(TraceContextPropagator::new()),
    ])
}

//! Utility functions for environment variable parsing and handling.
//!
//! This module provides a set of functions to parse environment variables
//! into various types, including vectors and durations. It also includes
//! functions for handling fallback values and optional durations.

use std::env;
use std::fmt::Display;
use std::str::FromStr;
use std::time::Duration;

/// Retrieves and parses an environment variable into the specified type.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
///
/// # Returns
///
/// A `Result` containing the parsed value or an error message.
///
/// # Errors
///
/// Returns an error if:
/// - The environment variable is not set
/// - The value cannot be parsed into the specified type
pub fn from_env<T>(env_var: &str) -> Result<T, String>
where
    T: FromStr<Err: Display>,
{
    let value_str = get_env_value(env_var)?;
    parse_with_error(env_var, &value_str)
}

/// Retrieves and parses an environment variable with a fallback value.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
/// * `fallback` - The fallback value to use if the environment variable is not
///   set.
///
/// # Returns
///
/// A `Result` containing the parsed value (or fallback) or an error message.
///
/// # Errors
///
/// Returns an error if the environment variable is set but cannot be parsed
/// into the specified type.
pub fn from_env_with_fallback<T>(env_var: &str, fallback: T) -> Result<T, String>
where
    T: FromStr<Err: Display>,
{
    let Ok(value_str) = env::var(env_var) else {
        return Ok(fallback);
    };

    parse_with_error(env_var, &value_str)
}

/// Retrieves and parses a comma-separated environment variable into a vector.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
///
/// # Returns
///
/// A `Result` containing a vector of parsed values or an error message.
///
/// # Errors
///
/// Returns an error if:
/// - The environment variable is not set
/// - Any of the comma-separated values cannot be parsed into the specified type
pub fn from_vec_env<T>(env_var: &str) -> Result<Vec<T>, String>
where
    T: FromStr<Err: Display>,
{
    get_env_value(env_var)?
        .split(',')
        .map(|value_str| parse_with_error(env_var, value_str))
        .collect()
}

/// Retrieves and parses a duration environment variable with a fallback value.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
/// * `fallback` - The fallback duration to use if the environment variable is
///   not set.
///
/// # Returns
///
/// A `Result` containing the parsed duration (or fallback) or an error message.
///
/// # Errors
///
/// Returns an error if the environment variable is set but cannot be parsed as
/// a valid duration.
pub fn from_duration_env_with_fallback(
    env_var: &str,
    fallback: Duration,
) -> Result<Duration, String> {
    let Ok(value_str) = env::var(env_var) else {
        return Ok(fallback);
    };

    parse_duration_with_error(env_var, &value_str)
}

/// Retrieves and parses an optional duration environment variable with a
/// fallback value.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
/// * `fallback` - The fallback duration to use if the environment variable is
///   not set.
///
/// # Returns
///
/// A `Result` containing an `Option<Duration>` or an error message.
///
/// # Errors
///
/// Returns an error if the environment variable is set but cannot be parsed as
/// a valid duration (unless the value is "none", which returns `Ok(None)`).
pub fn from_option_duration_env_with_fallback(
    env_var: &str,
    fallback: Duration,
) -> Result<Option<Duration>, String> {
    let Ok(value_str) = env::var(env_var) else {
        return Ok(Some(fallback));
    };

    // Check if the value is "none" (case-insensitive) to return None
    if value_str.eq_ignore_ascii_case("none") {
        return Ok(None);
    }

    parse_duration_with_error(env_var, &value_str).map(Some)
}

/// Parses a string value into the specified type, providing a formatted error
/// message.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable (for error reporting).
/// * `value_str` - The string value to parse.
///
/// # Returns
///
/// A `Result` containing the parsed value or a formatted error message.
///
/// # Errors
///
/// Returns an error if the string value cannot be parsed into the specified
/// type.
fn parse_with_error<T>(env_var: &str, value_str: &str) -> Result<T, String>
where
    T: FromStr<Err: Display>,
{
    value_str
        .parse()
        .map_err(|error| format!("failed to parse environment variable '${env_var}': {error:#}"))
}

/// Retrieves the value of an environment variable.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable to retrieve.
///
/// # Returns
///
/// A `Result` containing the environment variable value or an error message.
///
/// # Errors
///
/// Returns an error if the environment variable is not set.
fn get_env_value(env_var: &str) -> Result<String, String> {
    env::var(env_var).map_err(|_| {
        format!("value required and fallback environment variable '${env_var}' is not set")
    })
}

/// Parses a string value into a `Duration`, providing a formatted error
/// message.
///
/// # Arguments
///
/// * `env_var` - The name of the environment variable (for error reporting).
/// * `value_str` - The string value to parse.
///
/// # Returns
///
/// A `Result` containing the parsed `Duration` or a formatted error message.
///
/// # Errors
///
/// Returns an error if the string value cannot be parsed as a valid duration.
fn parse_duration_with_error(env_var: &str, value_str: &str) -> Result<Duration, String> {
    match humantime::Duration::from_str(value_str) {
        Ok(duration) => Ok(duration.into()),
        Err(error) => Err(format!(
            "failed to parse environment variable '${env_var}': {error:#}"
        )),
    }
}

//! Integration tests for the Prosody Kafka client library.
//!
//! This module contains a property-based integration test using `QuickCheck`
//! that verifies the correct functioning of the Prosody Kafka client library,
//! focusing on message ordering and completeness across multiple producers
//! and consumers.
//!
//! ## Test Overview
//!
//! The test is designed as a `QuickCheck` property, which means it's run
//! multiple times with randomly generated inputs. This approach helps to
//! explore a wide range of scenarios and increase confidence in the library's
//! robustness.
//!
//! For each run, the test simulates a scenario with multiple producers sending
//! messages to a Kafka topic and multiple consumers reading from that topic.
//! It verifies that:
//! 1. All messages are received.
//! 2. Messages for each key are received in the correct order.
//!
//! ## Test Parameters
//!
//! `QuickCheck` randomly generates the following parameters for each test run:
//! - `messages`: A map of keys to sets of message values.
//! - `partition_count`: The number of partitions in the Kafka topic.
//! - `producer_count`: The number of concurrent producers.
//! - `consumer_count`: The number of concurrent consumers.
//! - `max_enqueued_per_key`: Maximum number of messages to enqueue per key.
//!
//! ## Test Procedure
//!
//! 1. Create a Kafka topic with the specified number of partitions.
//! 2. Spawn multiple producer tasks, each sending a subset of the messages.
//! 3. Spawn multiple consumer tasks to read the messages.
//! 4. Collect and verify the received messages.
//!
//! ## Message Types
//!
//! The test uses two types of messages:
//! 1. Regular messages: JSON-encoded numbers.
//! 2. End-of-stream marker: A `null` value sent after all regular messages for
//!    a key.
//!
//! ## Completion Detection
//!
//! The test knows it's complete when it has received an end-of-stream marker
//! for every key in the input set. This ensures all messages have been
//! processed.
//!
//! ## Verification
//!
//! The test verifies correctness by:
//! 1. Checking that all expected messages are received.
//! 2. Ensuring messages for each key are received in the same order they were
//!    sent.
//!
//! ## Cleanup
//!
//! After each test run completes, it deletes the created Kafka topic to clean
//! up resources.
//!
//! This property-based test ensures that the Prosody library
//! correctly handles concurrent producers and consumers while maintaining
//! message ordering and completeness, which are crucial for many Kafka-based
//! applications. By using `QuickCheck`, the test can explore a wide range of
//! scenarios, increasing confidence in the library's correctness and
//! robustness.

use std::cmp::max;
use std::collections::BTreeSet;
use std::fmt::{Debug, Formatter};
use std::time::Duration;

use ahash::{HashMap, HashMapExt, HashSet};
use color_eyre::eyre::{eyre, OptionExt, Result};
use color_eyre::Report;
use derive_quickcheck_arbitrary::Arbitrary;
use itertools::Itertools;
use quickcheck::{Arbitrary, Gen, QuickCheck, TestResult};
use rdkafka::admin::{AdminClient, AdminOptions, NewTopic, TopicReplication};
use rdkafka::client::DefaultClientContext;
use rdkafka::config::FromClientConfig;
use rdkafka::ClientConfig;
use serde_json::{json, Value};
use tokio::runtime::Builder;
use tokio::sync::mpsc::{channel, Sender};
use tokio::sync::watch;
use tokio::task::JoinSet;
use tracing::{error, info};
use tracing_subscriber::fmt;
use uuid::Uuid;

use prosody::consumer::message::{ConsumerMessage, MessageContext};
use prosody::consumer::{ConsumerConfiguration, MessageHandler, ProsodyConsumer};
use prosody::producer::{ProducerConfiguration, ProsodyProducer};
use prosody::Topic;

/// Runs the main integration test to verify message ordering and completeness.
#[test]
fn receives_all_in_key_order() {
    const TEST_COUNT: u64 = 1;

    // Initialize tracing for better test output
    fmt().compact().init();

    // Run the QuickCheck property-based test
    QuickCheck::new()
        .tests(TEST_COUNT)
        .quickcheck(prop as fn(TestInput) -> TestResult);
}

/// Represents the input for each test run.
#[derive(Clone, Debug, Arbitrary)]
struct TestInput {
    messages: HashMap<u64, BTreeSet<u64>>,
    partition_count: SmallCount,
    producer_count: SmallCount,
    consumer_count: SmallCount,
    max_enqueued_per_key: SmallCount,
}

/// Defines the property to be tested.
fn prop(input: TestInput) -> TestResult {
    // Validate input data
    if input.messages.is_empty() || input.messages.values().any(BTreeSet::is_empty) {
        return TestResult::discard();
    }

    // Initialize the runtime for async operations
    let Ok(runtime) = Builder::new_multi_thread().enable_time().build() else {
        return TestResult::error("failed to initialize runtime");
    };

    // Run the test implementation
    match runtime.block_on(run_test(input)) {
        Ok(()) => TestResult::passed(),
        Err(e) => {
            error!("test failed with error: {e:#}");
            TestResult::error(e.to_string())
        }
    }
}

/// Runs the core logic of the integration test.
///
/// # Arguments
/// * `input` - The test input parameters.
///
/// # Errors
/// Returns an error if any part of the test setup or execution fails.
async fn run_test(input: TestInput) -> Result<()> {
    let (topic, admin_client) = create_test_topic(input.partition_count).await?;
    let (producer_config, consumer_config) = create_configs(&topic, input.max_enqueued_per_key)?;

    let (messages_tx, messages_rx) = channel(input.partition_count.value());
    let (shutdown_tx, shutdown_rx) = watch::channel(false);
    let handler = TestHandler::new(messages_tx);

    let mut tasks = JoinSet::new();

    spawn_producers(&mut tasks, &input, &producer_config, &topic);
    spawn_consumers(
        &mut tasks,
        input.consumer_count,
        &consumer_config,
        &handler,
        &shutdown_rx,
    );
    spawn_message_verifier(&mut tasks, messages_rx, shutdown_tx, input.messages);

    // Wait for all tasks to complete
    while let Some(result) = tasks.join_next().await {
        result??;
    }

    info!("test passed");

    // Delete the test topic
    let admin_options = AdminOptions::default().operation_timeout(Some(Duration::from_secs(5)));
    admin_client
        .delete_topics(&[topic.as_ref()], &admin_options)
        .await?;

    info!("deleted test topic: {topic}");

    Ok(())
}

/// Creates a test topic and returns its name along with the admin client.
///
/// # Arguments
/// * `partition_count` - The number of partitions for the test topic.
///
/// # Errors
/// Returns an error if topic creation fails.
async fn create_test_topic(
    partition_count: SmallCount,
) -> Result<(Topic, AdminClient<DefaultClientContext>)> {
    let topic: Topic = Uuid::new_v4().to_string().as_str().into();
    let mut config = ClientConfig::new();
    config.set("bootstrap.servers", "localhost:9094");

    let admin_options = AdminOptions::default().operation_timeout(Some(Duration::from_secs(5)));
    let admin_client = AdminClient::from_config(&config)?;

    admin_client
        .create_topics(
            &[NewTopic::new(
                &topic,
                partition_count.value() as i32,
                TopicReplication::Fixed(1),
            )],
            &admin_options,
        )
        .await?;

    info!("created topic: {topic}");
    Ok((topic, admin_client))
}

/// Creates producer and consumer configurations.
///
/// # Arguments
/// * `topic` - The name of the test topic.
/// * `max_enqueued_per_key` - Maximum number of messages to enqueue per key.
///
/// # Errors
/// Returns an error if configuration creation fails.
fn create_configs(
    topic: &Topic,
    max_enqueued_per_key: SmallCount,
) -> Result<(ProducerConfiguration, ConsumerConfiguration)> {
    let bootstrap: Vec<String> = vec!["localhost:9094".to_owned()];
    let producer_config = ProducerConfiguration::builder()
        .bootstrap_servers(bootstrap.clone())
        .build()?;

    let consumer_config = ConsumerConfiguration::builder()
        .bootstrap_servers(bootstrap)
        .group_id("test-consumer")
        .subscribed_topics(&[topic.to_string()])
        .max_enqueued_per_key(max_enqueued_per_key.value())
        .commit_interval(Duration::from_secs(1))
        .partition_shutdown_timeout(Some(Duration::from_secs(60)))
        .build()?;

    Ok((producer_config, consumer_config))
}

/// Spawns producer tasks.
///
/// # Arguments
/// * `tasks` - The `JoinSet` to add tasks to.
/// * `input` - The test input parameters.
/// * `producer_config` - The producer configuration.
/// * `topic` - The name of the test topic.
fn spawn_producers(
    tasks: &mut JoinSet<Result<()>>,
    input: &TestInput,
    producer_config: &ProducerConfiguration,
    topic: &Topic,
) {
    let message_count = input.messages.len();
    let producer_message_count = max(message_count / input.producer_count.value(), 1);

    for producer_messages in input
        .messages
        .clone()
        .into_iter()
        .chunks(producer_message_count)
        .into_iter()
        .map(Iterator::collect::<Vec<_>>)
    {
        let producer_config = producer_config.clone();
        let topic = *topic;

        tasks.spawn(async move {
            let producer = ProsodyProducer::new(&producer_config)?;
            for (key, messages) in producer_messages {
                let key = key.to_string();
                for message in messages {
                    producer.send(topic, &key, json!(message)).await?;
                }
                producer.send(topic, &key, Value::Null).await?;
            }
            Ok(())
        });
    }
}

/// Spawns consumer tasks.
///
/// # Arguments
/// * `tasks` - The `JoinSet` to add tasks to.
/// * `consumer_count` - The number of consumers to spawn.
/// * `consumer_config` - The consumer configuration.
/// * `handler` - The message handler.
/// * `shutdown_rx` - The shutdown signal receiver.
fn spawn_consumers(
    tasks: &mut JoinSet<Result<()>>,
    consumer_count: SmallCount,
    consumer_config: &ConsumerConfiguration,
    handler: &TestHandler,
    shutdown_rx: &watch::Receiver<bool>,
) {
    for _ in 0..consumer_count.value() {
        let consumer_config = consumer_config.clone();
        let handler = handler.clone();
        let mut shutdown_rx = shutdown_rx.clone();

        tasks.spawn(async move {
            let consumer = ProsodyConsumer::new(consumer_config, handler)?;
            shutdown_rx.wait_for(|is_shutdown| *is_shutdown).await?;
            consumer.shutdown().await;
            Ok(())
        });
    }
}

/// Spawns a task to receive and verify messages.
///
/// # Arguments
/// * `tasks` - The `JoinSet` to add the task to.
/// * `messages_rx` - The channel receiver for incoming messages.
/// * `shutdown_tx` - The shutdown signal sender.
/// * `expected_messages` - The expected messages to be received.
fn spawn_message_verifier(
    tasks: &mut JoinSet<Result<()>>,
    mut messages_rx: tokio::sync::mpsc::Receiver<(String, Value)>,
    shutdown_tx: watch::Sender<bool>,
    expected_messages: HashMap<u64, BTreeSet<u64>>,
) {
    tasks.spawn(async move {
        let mut keys: HashSet<String> = expected_messages.keys().map(ToString::to_string).collect();
        let mut received: HashMap<String, Vec<u64>> =
            HashMap::with_capacity(expected_messages.len());

        info!("receiving messages");
        while let Some((key, payload)) = messages_rx.recv().await {
            match payload {
                Value::Number(number) => {
                    let number = number.as_u64().ok_or_eyre("invalid number")?;
                    received.entry(key).or_default().push(number);
                }
                Value::Null => {
                    keys.remove(&key);
                    if keys.is_empty() {
                        break;
                    }
                }
                _ => return Err(eyre!("unexpected payload type")),
            }
        }

        verify_results(&expected_messages, received)?;

        info!("sending shutdown signal");
        shutdown_tx.send(true)?;

        Ok(())
    });
}

/// Verifies that received messages match expected messages.
///
/// # Arguments
/// * `expected` - The expected messages.
/// * `received` - The received messages.
///
/// # Errors
/// Returns an error if received messages don't match expected messages.
fn verify_results(
    expected: &HashMap<u64, BTreeSet<u64>>,
    received: HashMap<String, Vec<u64>>,
) -> Result<()> {
    let mut actual: HashMap<u64, BTreeSet<u64>> = HashMap::with_capacity(expected.len());

    for (key, received_messages) in received {
        let key: u64 = key.parse()?;
        let received_set: BTreeSet<u64> = received_messages.iter().copied().collect();
        actual.insert(key, received_set);

        let mut sorted = received_messages.clone();
        sorted.sort_unstable();

        if received_messages != sorted {
            return Err(eyre!(
                "invalid order for key {key}; expected: {sorted:?}, actual: {received_messages:?}"
            ));
        }
    }

    if *expected != actual {
        return Err(eyre!(
            "all messages were not received; expected: {expected:?}, actual: {actual:?}"
        ));
    }

    Ok(())
}

/// A test implementation of the `MessageHandler` trait.
#[derive(Clone, Debug)]
struct TestHandler {
    messages_tx: Sender<(String, Value)>,
}

impl TestHandler {
    /// Creates a new `TestHandler` instance.
    ///
    /// # Arguments
    /// * `messages_tx` - A channel sender for passing received messages.
    fn new(messages_tx: Sender<(String, Value)>) -> Self {
        Self { messages_tx }
    }
}

impl MessageHandler for TestHandler {
    type Error = Report;

    /// Handles a received message by sending it through the channel.
    ///
    /// # Arguments
    /// * `_context` - The message context (unused in this implementation).
    /// * `message` - The received consumer message.
    ///
    /// # Returns
    /// A Result indicating success or failure of the message handling.
    ///
    /// # Errors
    /// Returns an error if sending the message through the channel fails.
    async fn handle(
        &self,
        _context: &mut MessageContext,
        message: ConsumerMessage,
    ) -> Result<(), Self::Error> {
        let (key, payload, uncommitted) = message.into_inner();
        self.messages_tx.send((key.to_string(), payload)).await?;
        uncommitted.commit();
        Ok(())
    }
}

/// A wrapper for small, non-zero random numbers used in testing.
#[derive(Copy, Clone)]
struct SmallCount(u8);

impl SmallCount {
    /// Returns the wrapped value as a usize.
    fn value(self) -> usize {
        self.0 as usize
    }
}

impl Arbitrary for SmallCount {
    /// Generates a small, non-zero random number.
    fn arbitrary(g: &mut Gen) -> Self {
        const VALUES: [u8; 12] = const_array();
        Self(*max(&1, g.choose(&VALUES).unwrap_or(&1)))
    }
}

impl Debug for SmallCount {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.0)
    }
}

/// Generates a constant array of sequential u8 values.
///
/// # Returns
/// An array of sequential u8 values from 1 to N.
const fn const_array<const N: usize>() -> [u8; N] {
    let mut arr = [0; N];
    let mut i = 0;
    while i < N {
        arr[i] = i as u8 + 1;
        i += 1;
    }
    arr
}
